window.QUESTION_BANK = {"meta":{"title":"Ngân hàng 200 câu hỏi truyền thống 80 năm Pháo binh - Tên lửa","mcq_count":100,"true_false_count":100,"source_file":"200_cau_hoi_truyen_thong_80_nam_Phao_binh_Ten_lua(1).docx"},"mcqQuestions":[{"num":1,"question":"Ngày truyền thống của Bộ đội Pháo binh - Tên lửa là ngày nào?","options":{"A":"19/12/1946","B":"29/6/1946","C":"7/5/1954","D":"30/4/1975"},"answer":"B","explanation":"29/6/1946\nGiải thích mở rộng: Ngày 29/6/1946, tại trại Vệ quốc đoàn Trung ương ở số 40 Hàng Bài, Bộ Quốc phòng công bố quyết định thành lập Đoàn Pháo binh Thủ đô. Đây là mốc đánh dấu sự ra đời chính thức của pháo binh cách mạng Việt Nam với tổ chức chỉ huy, huấn luyện và chiến đấu tương đối thống nhất.\nÝ nghĩa: Mốc này mở đầu chặng đường 80 năm xây dựng, chiến đấu, chiến thắng và trưởng thành của lực lượng pháo binh - tên lửa, khẳng định vị trí của hỏa lực chủ yếu mặt đất trong Quân đội nhân dân Việt Nam."},{"num":2,"question":"Đơn vị pháo binh đầu tiên của Quân đội nhân dân Việt Nam là đơn vị nào?","options":{"A":"Trung đoàn 675","B":"Đại đoàn 351","C":"Đoàn Pháo binh Thủ đô","D":"Cục Pháo binh"},"answer":"C","explanation":"Đoàn Pháo binh Thủ đô\nGiải thích mở rộng: Đoàn Pháo binh Thủ đô được thành lập ngày 29/6/1946 gồm ba trung đội: Pháo đài Láng, Pháo đài Xuân Tảo và Pháo đài Xuân Canh. Sự kiện này đánh dấu từ chỗ có pháo nhưng chưa có tổ chức chuyên trách sang có lực lượng pháo binh được tổ chức thành đơn vị riêng.\nÝ nghĩa: Đây là lực lượng nòng cốt ban đầu, đặt nền móng cho sự phát triển sau này của các tiểu đoàn, trung đoàn, đại đoàn và Bộ Tư lệnh Pháo binh - Tên lửa."},{"num":3,"question":"Sự kiện nào trực tiếp đánh dấu sự ra đời của Pháo binh Việt Nam?","options":{"A":"Thành lập Cục Pháo binh","B":"Thành lập Đoàn Pháo binh Thủ đô","C":"Thành lập Đại đoàn 351","D":"Thành lập Trường Sĩ quan Pháo binh"},"answer":"B","explanation":"Thành lập Đoàn Pháo binh Thủ đô\nGiải thích mở rộng: Việc thành lập Đoàn Pháo binh Thủ đô là cột mốc ra đời chính thức của pháo binh Việt Nam. Trước đó, ta đã có vũ khí pháo thu được từ quân thù, nhưng chưa hình thành lực lượng pháo binh chuyên trách với tổ chức tương đối hoàn chỉnh.\nÝ nghĩa: Câu hỏi giúp xác định đúng cột mốc lịch sử gốc của lực lượng, tránh nhầm với các mốc phát triển sau này như Cục Pháo binh hay Bộ Tư lệnh Pháo binh."},{"num":4,"question":"Phát đạn đầu tiên mở màn toàn quốc kháng chiến được bắn từ đâu?","options":{"A":"Đoan Hùng","B":"Him Lam","C":"Pháo đài Láng","D":"Xuân Canh"},"answer":"C","explanation":"Pháo đài Láng\nGiải thích mở rộng: Lúc 20 giờ 03 phút ngày 19/12/1946, Pháo đài Láng nổ phát đạn đầu tiên vào quân Pháp trong thành Hà Nội, mở đầu toàn quốc kháng chiến. Sự kiện này gắn liền với những ngày đầu bộ đội pháo binh bước vào thử thách lớn của dân tộc.\nÝ nghĩa: Điều đó khẳng định pháo binh không chỉ chi viện mà còn có thể mở màn chiến đấu, tạo thế chủ động cho toàn quân và toàn dân kháng chiến."},{"num":5,"question":"Chiến thắng Sông Lô năm 1947 nổi bật với cách đánh nào của pháo binh?","options":{"A":"Đánh du kích phân tán","B":"Đặt gần bắn thẳng","C":"Vây lấn dài ngày","D":"Đánh vào ban đêm là chủ yếu"},"answer":"B","explanation":"Đặt gần bắn thẳng\nGiải thích mở rộng: Trong chiến dịch Việt Bắc Thu - Đông 1947, bộ đội pháo binh trên sông Lô đã sáng tạo cách đánh “đặt gần bắn thẳng”, đưa pháo vào gần mục tiêu để tăng độ chính xác và sức công phá. Cách đánh này đòi hỏi dũng cảm, bí mật và hiệp đồng chặt chẽ.\nÝ nghĩa: Đây là biểu hiện sớm của tư duy quân sự sáng tạo Việt Nam, cho thấy pháo binh biết lấy yếu thắng mạnh bằng cách đánh phù hợp thực tế chiến trường."},{"num":6,"question":"Tiểu đoàn pháo binh đầu tiên của Quân đội ta là đơn vị nào?","options":{"A":"Tiểu đoàn 410","B":"Tiểu đoàn 45","C":"Tiểu đoàn 351","D":"Tiểu đoàn 204"},"answer":"A","explanation":"Tiểu đoàn 410\nGiải thích mở rộng: Đến năm 1949, Quân đội ta thành lập tiểu đoàn pháo binh đầu tiên là Tiểu đoàn 410. Đây là bước phát triển về tổ chức rất quan trọng, từ các trung đội, khẩu đội nhỏ tiến lên quy mô tiểu đoàn.\nÝ nghĩa: Mốc này thể hiện sự trưởng thành của pháo binh về tổ chức chỉ huy, huấn luyện và khả năng tham gia hiệp đồng trong các chiến dịch lớn."},{"num":7,"question":"Cục Pháo binh được thành lập vào năm nào?","options":{"A":"1946","B":"1947","C":"1949","D":"1951"},"answer":"C","explanation":"1949\nGiải thích mở rộng: Ngày 18/6/1949, theo Sắc lệnh số 50/SL của Chủ tịch Hồ Chí Minh, Cục Pháo binh được thành lập. Cục có nhiệm vụ nghiên cứu, chế tạo, sửa chữa pháo đạn và đào tạo cán bộ chỉ huy pháo binh sơ cấp.\nÝ nghĩa: Sự ra đời của Cục Pháo binh tạo cơ sở quan trọng để xây dựng lực lượng theo hướng thống nhất, chính quy và chuyên môn hóa hơn."},{"num":8,"question":"Người phụ trách Cục Pháo binh đầu tiên là ai?","options":{"A":"Võ Nguyên Giáp","B":"Nguyễn Chánh","C":"Lê Thiết Hùng","D":"Trần Đại Nghĩa"},"answer":"D","explanation":"Trần Đại Nghĩa\nGiải thích mở rộng: Đồng chí Trần Đại Nghĩa là người phụ trách Cục Pháo binh đầu tiên. Ông là nhà khoa học quân sự xuất sắc, có đóng góp lớn trong nghiên cứu, cải tiến và chế tạo vũ khí phục vụ kháng chiến.\nÝ nghĩa: Câu hỏi nhấn mạnh vai trò của trí thức, khoa học - công nghệ đối với quá trình hình thành và phát triển sức mạnh pháo binh Việt Nam."},{"num":9,"question":"Đại đoàn Công pháo 351 được thành lập vào thời gian nào?","options":{"A":"Tháng 3/1951","B":"Tháng 6/1949","C":"Tháng 11/1950","D":"Tháng 5/1954"},"answer":"A","explanation":"Tháng 3/1951\nGiải thích mở rộng: Tháng 3/1951, Đại đoàn Công pháo 351 được thành lập gồm Trung đoàn sơn pháo 675, Trung đoàn lựu pháo 45 và Trung đoàn Công binh 151. Đây là đơn vị công pháo chủ lực có vai trò rất lớn trong các chiến dịch lớn sau đó.\nÝ nghĩa: Việc thành lập Đại đoàn 351 là bước nhảy vọt của pháo binh từ quy mô trung đoàn lên quy mô đại đoàn, tạo nền tảng cho tác chiến hiệp đồng binh chủng."},{"num":10,"question":"Trung đoàn 675 được thành lập trên cơ sở tiền thân là đơn vị nào?","options":{"A":"Trung đoàn 34","B":"Trung đoàn 95","C":"Tiểu đoàn 410","D":"Trung đoàn 151"},"answer":"B","explanation":"Trung đoàn 95\nGiải thích mở rộng: Ngày 20/11/1950, Trung đoàn 675 được thành lập, tiền thân là Trung đoàn 95. Đây là trung đoàn sơn pháo đầu tiên của binh chủng, có nhiều chiến công lớn trong kháng chiến chống Pháp và chống Mỹ.\nÝ nghĩa: Mốc này cho thấy pháo binh đã phát triển nhanh cả về quy mô tổ chức lẫn khả năng cơ động, chiến đấu trên các địa hình khó khăn."},{"num":11,"question":"Trung đoàn pháo xe kéo đầu tiên của Quân đội ta là đơn vị nào?","options":{"A":"Trung đoàn 45","B":"Trung đoàn 675","C":"Trung đoàn 208","D":"Trung đoàn 96"},"answer":"A","explanation":"Trung đoàn 45\nGiải thích mở rộng: Cuối năm 1950, Trung đoàn 34 được lựa chọn xây dựng thành Trung đoàn pháo binh cơ giới đầu tiên của Quân đội nhân dân Việt Nam; sau đó đổi phiên hiệu thành Trung đoàn 45. Đây là trung đoàn pháo xe kéo đầu tiên của ta.\nÝ nghĩa: Câu hỏi giúp nhận diện một mốc rất quan trọng trong quá trình hiện đại hóa phương tiện, tổ chức và phương pháp cơ động của pháo binh."},{"num":12,"question":"Trong Chiến dịch Điện Biên Phủ, đơn vị nào được bắn phát đạn đầu tiên vào cứ điểm Him Lam?","options":{"A":"Đại đội 806, Trung đoàn 45","B":"Tiểu đoàn 410","C":"Trung đoàn 675","D":"Đại đội 1, Trung đoàn 151"},"answer":"A","explanation":"Đại đội 806, Trung đoàn 45\nGiải thích mở rộng: Đúng 17 giờ 05 phút ngày 13/3/1954, Đại đội pháo 806 của Trung đoàn 45 vinh dự bắn phát đạn đầu tiên vào cứ điểm Him Lam, mở màn Chiến dịch Điện Biên Phủ. Hỏa lực pháo binh đã tạo điều kiện rất lớn cho bộ binh tiến công.\nÝ nghĩa: Sự kiện này khẳng định vai trò mở màn, đột phá và chi viện cực kỳ quan trọng của pháo binh trong chiến dịch lịch sử Điện Biên Phủ."},{"num":13,"question":"Ngày 25/02/1954, Đảng ủy và Bộ Tư lệnh Đại đoàn 351 thông qua kế hoạch sử dụng pháo binh cho chiến dịch nào?","options":{"A":"Chiến dịch Biên giới","B":"Chiến dịch Tây Bắc","C":"Chiến dịch Điện Biên Phủ","D":"Chiến dịch Hòa Bình"},"answer":"C","explanation":"Chiến dịch Điện Biên Phủ\nGiải thích mở rộng: Ngày 25/02/1954, Đảng ủy và Bộ Tư lệnh Đại đoàn 351 họp thông qua kế hoạch sử dụng pháo binh theo quyết tâm của Bộ chỉ huy Chiến dịch Điện Biên Phủ. Từ đây, pháo binh được tổ chức, bố trí và hiệp đồng rất chặt chẽ.\nÝ nghĩa: Mốc này cho thấy vai trò chủ động tham gia chuẩn bị chiến dịch của pháo binh và tầm quan trọng của chỉ huy, hiệp đồng trong chiến tranh hiện đại."},{"num":14,"question":"Trong Chiến dịch Điện Biên Phủ, lần đầu tiên hỏa tiễn nào của ta xuất hiện, gây bất ngờ lớn cho địch?","options":{"A":"H12","B":"A12","C":"H06","D":"BM-21"},"answer":"C","explanation":"H06\nGiải thích mở rộng: Ở đợt 3 Chiến dịch Điện Biên Phủ, ta đưa thêm Tiểu đoàn hỏa tiễn H06 vào chiến đấu. Sự xuất hiện của hỏa tiễn H06 đã gây bất ngờ lớn, làm cho địch hoang mang và tăng hiệu quả chế áp các mục tiêu tập trung.\nÝ nghĩa: Điều này cho thấy pháo binh Việt Nam không ngừng tiếp thu, làm chủ và vận dụng các loại hỏa lực mới để tăng sức mạnh chiến đấu."},{"num":15,"question":"Ai là một trong hai đồng chí của Trung đoàn 675 được tuyên dương danh hiệu Anh hùng Quân đội sau kháng chiến chống Pháp?","options":{"A":"Phùng Văn Khầu","B":"Lê Thiết Hùng","C":"Nguyễn Chánh","D":"Tô Na"},"answer":"A","explanation":"Phùng Văn Khầu\nGiải thích mở rộng: Sau kháng chiến chống Pháp, hai đồng chí của Trung đoàn 675 được tuyên dương danh hiệu Anh hùng Quân đội là Bùi Đình Cầu và Phùng Văn Khầu. Phùng Văn Khầu nổi tiếng với tinh thần chiến đấu ngoan cường trong Chiến dịch Điện Biên Phủ.\nÝ nghĩa: Câu hỏi góp phần giáo dục truyền thống anh hùng, tinh thần quyết chiến quyết thắng và ý chí vượt khó của cán bộ, chiến sĩ pháo binh."},{"num":16,"question":"Ngày 07/9/1954, Bộ Quốc phòng - Tổng Tư lệnh thành lập cơ quan chỉ huy nào của pháo binh?","options":{"A":"Bộ Tư lệnh Pháo binh","B":"Bộ Chỉ huy Pháo binh","C":"Đảng bộ Binh chủng Pháo binh","D":"Trường Sĩ quan Pháo binh"},"answer":"B","explanation":"Bộ Chỉ huy Pháo binh\nGiải thích mở rộng: Ngày 07/9/1954, Bộ Quốc phòng - Tổng Tư lệnh ra nghị định thành lập Bộ Chỉ huy Pháo binh. Đây là cơ quan chỉ huy đầu tiên của pháo binh sau hòa bình lập lại ở miền Bắc, đáp ứng yêu cầu xây dựng lực lượng trong giai đoạn mới.\nÝ nghĩa: Mốc này đánh dấu quá trình củng cố, tổ chức lại lực lượng pháo binh quy mô lớn sau chiến thắng Điện Biên Phủ."},{"num":17,"question":"Đồng chí nào được bổ nhiệm làm Tư lệnh kiêm Chính ủy Bộ Chỉ huy Pháo binh khi đơn vị này thành lập năm 1954?","options":{"A":"Nguyễn Chánh","B":"Lê Thiết Hùng","C":"Phạm Ngọc Mậu","D":"Trần Đại Nghĩa"},"answer":"A","explanation":"Nguyễn Chánh\nGiải thích mở rộng: Khi Bộ Chỉ huy Pháo binh được thành lập ngày 07/9/1954, đồng chí Nguyễn Chánh được bổ nhiệm làm Tư lệnh kiêm Chính ủy. Bộ máy chỉ huy này có vai trò quan trọng trong việc ổn định, xây dựng và phát triển lực lượng pháo binh sau chiến tranh chống Pháp.\nÝ nghĩa: Câu hỏi làm rõ vai trò của đội ngũ lãnh đạo đầu tiên trong thời kỳ tổ chức, xây dựng lực lượng pháo binh chính quy ở miền Bắc."},{"num":18,"question":"Ngày 28/5/1956, Bộ Chỉ huy Pháo binh được đổi tên thành gì?","options":{"A":"Bộ Chỉ huy Hỏa lực","B":"Bộ Tư lệnh Pháo binh","C":"Bộ Tư lệnh Tên lửa","D":"Cục Pháo binh"},"answer":"B","explanation":"Bộ Tư lệnh Pháo binh\nGiải thích mở rộng: Ngày 28/5/1956, Bộ Quốc phòng - Tổng Tư lệnh ra chỉ thị đổi tên Bộ Chỉ huy Pháo binh thành Bộ Tư lệnh Pháo binh. Đây là bước trưởng thành lớn về tổ chức, thể hiện vị trí ngày càng cao của binh chủng trong Quân đội.\nÝ nghĩa: Đổi tên không chỉ mang ý nghĩa hành chính mà còn phản ánh sự phát triển cả về quy mô, chức năng và nhiệm vụ của lực lượng."},{"num":19,"question":"Thiếu tướng nào được bổ nhiệm làm Tư lệnh khi Bộ Tư lệnh Pháo binh được thành lập năm 1956?","options":{"A":"Nguyễn Chánh","B":"Lê Thiết Hùng","C":"Phạm Ngọc Mậu","D":"Trần Đại Nghĩa"},"answer":"B","explanation":"Lê Thiết Hùng\nGiải thích mở rộng: Khi Bộ Tư lệnh Pháo binh được thành lập ngày 28/5/1956, Thiếu tướng Lê Thiết Hùng được bổ nhiệm làm Tư lệnh. Dưới sự chỉ huy của Bộ Tư lệnh, lực lượng pháo binh tiếp tục được chấn chỉnh, tổ chức thống nhất và từng bước hiện đại hóa.\nÝ nghĩa: Việc kiện toàn chức danh Tư lệnh thể hiện sự trưởng thành của binh chủng về mặt chỉ huy chiến lược và tổ chức lực lượng."},{"num":20,"question":"Trường Sĩ quan Pháo binh được thành lập vào ngày nào?","options":{"A":"18/02/1957","B":"22/5/1959","C":"21/3/1958","D":"07/9/1954"},"answer":"A","explanation":"18/02/1957\nGiải thích mở rộng: Ngày 18/02/1957, Trường Sĩ quan Pháo binh được thành lập theo Nghị định số 32/NĐ của Bộ Quốc phòng. Nhà trường có vai trò đào tạo đội ngũ cán bộ pháo binh cho binh chủng và toàn quân.\nÝ nghĩa: Đây là mốc rất quan trọng về giáo dục - đào tạo, bảo đảm cho pháo binh phát triển lâu dài, vững chắc và chính quy."},{"num":21,"question":"Ngày 21/3/1958, lực lượng nào tách khỏi Bộ Tư lệnh Pháo binh để tổ chức Bộ Tư lệnh riêng?","options":{"A":"Pháo binh mặt đất","B":"Pháo dự bị","C":"Pháo cao xạ","D":"Tên lửa chiến thuật"},"answer":"C","explanation":"Pháo cao xạ\nGiải thích mở rộng: Ngày 21/3/1958, Sư đoàn pháo cao xạ 367 tách khỏi Bộ Tư lệnh Pháo binh để tổ chức Bộ Tư lệnh Phòng không. Việc điều chỉnh này phù hợp với yêu cầu phát triển từng lực lượng chuyên ngành trong Quân đội.\nÝ nghĩa: Câu hỏi phản ánh sự phân hóa, chuyên môn hóa ngày càng rõ trong tổ chức các binh chủng kỹ thuật của Quân đội nhân dân Việt Nam."},{"num":22,"question":"Đảng bộ Binh chủng Pháo binh được thành lập vào ngày nào?","options":{"A":"29/6/1946","B":"22/5/1959","C":"28/5/1956","D":"18/6/1949"},"answer":"B","explanation":"22/5/1959\nGiải thích mở rộng: Ngày 22/5/1959, Ban Bí thư Trung ương Đảng ra quyết định thành lập Đảng bộ Binh chủng Pháo binh. Đảng bộ có chức năng lãnh đạo toàn diện các đơn vị, cơ quan, nhà trường trực thuộc Bộ Tư lệnh.\nÝ nghĩa: Mốc này khẳng định vai trò lãnh đạo tuyệt đối, trực tiếp về mọi mặt của Đảng đối với lực lượng pháo binh."},{"num":23,"question":"Trong 10 năm xây dựng lực lượng 1954-1964, bộ đội pháo binh phát triển rộng ở những thành phần nào?","options":{"A":"Chỉ ở bộ đội chủ lực","B":"Chỉ ở bộ đội địa phương","C":"Chỉ ở dân quân tự vệ","D":"Ở bộ đội chủ lực, bộ đội địa phương và dân quân tự vệ"},"answer":"D","explanation":"Ở bộ đội chủ lực, bộ đội địa phương và dân quân tự vệ\nGiải thích mở rộng: Giai đoạn 1954-1964, pháo binh không chỉ phát triển trong khối chủ lực mà còn mở rộng ở bộ đội địa phương và dân quân tự vệ. Nhờ đó, thế trận hỏa lực của toàn dân, toàn quân được củng cố rộng khắp.\nÝ nghĩa: Ý nghĩa của việc phát triển đồng bộ là tạo thế trận pháo binh rộng, sâu, gắn chặt giữa quốc phòng toàn dân với chiến tranh nhân dân."},{"num":24,"question":"Trong cuộc Tổng tiến công và nổi dậy Xuân Mậu Thân 1968, pháo binh đã góp phần đánh vào đâu?","options":{"A":"Chỉ các căn cứ ven biển","B":"Chủ yếu vào cơ quan đầu não của Mỹ - ngụy","C":"Chỉ kho tàng hậu phương","D":"Chỉ sân bay chiến lược"},"answer":"B","explanation":"Chủ yếu vào cơ quan đầu não của Mỹ - ngụy\nGiải thích mở rộng: Trong Xuân Mậu Thân 1968, các lực lượng pháo binh tham gia tiến công vào hầu hết các cơ quan đầu não của Mỹ - ngụy trên toàn chiến trường. Hỏa lực pháo binh tạo tác động mạnh về quân sự và tâm lý đối với đối phương.\nÝ nghĩa: Vai trò của pháo binh trong Mậu Thân thể hiện khả năng chi viện hỏa lực táo bạo, bất ngờ, phối hợp với các hướng tiến công chiến lược."},{"num":25,"question":"Chiến dịch nào năm 1971 được tài liệu nhấn mạnh cùng với pháo binh trong cuộc kháng chiến chống Mỹ?","options":{"A":"Đường 9 - Nam Lào","B":"Điện Biên Phủ trên không","C":"Biên giới Thu - Đông","D":"Tây Nguyên 1975"},"answer":"A","explanation":"Đường 9 - Nam Lào\nGiải thích mở rộng: Tài liệu nêu rõ từ Chiến dịch Đường 9 - Nam Lào năm 1971 đến cuộc Tổng tiến công chiến lược 1972, pháo binh đã chi viện đắc lực cho các lực lượng đánh địch. Những chiến dịch này cho thấy trình độ hiệp đồng và sức mạnh hỏa lực của pháo binh ngày càng cao.\nÝ nghĩa: Đây là giai đoạn pháo binh trưởng thành mạnh về tổ chức, kỹ thuật và nghệ thuật sử dụng hỏa lực trong tác chiến quy mô lớn."},{"num":26,"question":"Trong cuộc Tổng tiến công chiến lược năm 1972, pháo binh góp phần phá vỡ tuyến phòng thủ kiên cố nhất của địch ở đâu?","options":{"A":"Bắc Quảng Trị","B":"Cao Bằng","C":"Điện Biên","D":"Ninh Bình"},"answer":"A","explanation":"Bắc Quảng Trị\nGiải thích mở rộng: Tài liệu nhấn mạnh năm 1972, pháo binh cùng các lực lượng đã góp phần phá vỡ tuyến phòng thủ kiên cố nhất của địch ở Bắc Quảng Trị, đồng thời đánh mạnh ở nhiều hướng khác như Lộc Ninh, Đường 13, Tây Nguyên.\nÝ nghĩa: Điều này cho thấy pháo binh giữ vai trò rất lớn trong tạo đột phá chiến dịch, chiến lược, làm thay đổi so sánh lực lượng trên chiến trường."},{"num":27,"question":"Trong Chiến dịch Hồ Chí Minh lịch sử, pháo binh hiệp đồng cùng lực lượng nào tiến vào giải phóng Sài Gòn?","options":{"A":"3 quân đoàn","B":"4 quân đoàn","C":"5 quân đoàn và nhiều lực lượng khác","D":"Chỉ lực lượng địa phương"},"answer":"C","explanation":"5 quân đoàn và nhiều lực lượng khác\nGiải thích mở rộng: Trong Chiến dịch Hồ Chí Minh, pháo binh tham gia hiệp đồng với quy mô 5 quân đoàn cùng nhiều lực lượng khác tiến vào giải phóng Sài Gòn. Hỏa lực pháo binh đã góp phần quan trọng tạo thế áp đảo đối với địch.\nÝ nghĩa: Đây là biểu hiện tập trung của sức mạnh hiệp đồng binh chủng và nghệ thuật sử dụng pháo binh trong chiến dịch quyết chiến chiến lược."},{"num":28,"question":"Ngày 05/8/1965, đế quốc Mỹ mở cuộc chiến tranh phá hoại ra miền Bắc. Pháo binh ta đã làm gì?","options":{"A":"Rút toàn bộ lực lượng về tuyến sau","B":"Chỉ làm nhiệm vụ huấn luyện","C":"Bắn rơi máy bay, bắn cháy và bắn chìm nhiều tàu chiến Mỹ","D":"Chỉ bảo vệ kho tàng"},"answer":"C","explanation":"Bắn rơi máy bay, bắn cháy và bắn chìm nhiều tàu chiến Mỹ\nGiải thích mở rộng: Từ ngày 05/8/1965, khi Mỹ mở rộng chiến tranh phá hoại ra miền Bắc, pháo binh ta đã kiên cường chiến đấu, bắn rơi máy bay và bắn cháy, bắn chìm nhiều tàu chiến, tàu tuần dương, tàu khu trục của Mỹ.\nÝ nghĩa: Sự kiện này khẳng định pháo binh không chỉ tác chiến trên bộ mà còn có khả năng đánh địch trên không, trên biển trong chiến tranh bảo vệ miền Bắc."},{"num":29,"question":"Ngày 13/4/1967, Bác Hồ gửi thư khen ngợi Bộ đội Pháo binh và tặng tám chữ vàng nào?","options":{"A":"Trung với Đảng, hiếu với dân","B":"Chân đồng vai sắt, đánh giỏi, bắn trúng","C":"Quyết chiến, quyết thắng, đoàn kết","D":"Tất cả vì tiền tuyến lớn"},"answer":"B","explanation":"Chân đồng vai sắt, đánh giỏi, bắn trúng\nGiải thích mở rộng: Ngày 13/4/1967, trước những chiến công vang dội của pháo binh trên cả hai miền, Bác Hồ gửi thư khen và tặng tám chữ vàng: “Chân đồng vai sắt, đánh giỏi, bắn trúng”. Đây là kết tinh cao đẹp của phẩm chất và nghệ thuật chiến đấu pháo binh.\nÝ nghĩa: Tám chữ vàng trở thành truyền thống tiêu biểu, là niềm tự hào, phương châm hành động và mục tiêu phấn đấu của các thế hệ pháo binh - tên lửa."},{"num":30,"question":"Trong thư khen năm 1967, Bác Hồ còn căn dặn bộ đội pháo binh điều gì?","options":{"A":"Chỉ tập trung đánh lớn","B":"Không cần học tập thêm","C":"Chớ vì thắng lợi mà chủ quan, phải học tập và giữ gìn pháo xe tốt","D":"Ưu tiên kinh tế hơn quốc phòng"},"answer":"C","explanation":"Chớ vì thắng lợi mà chủ quan, phải học tập và giữ gìn pháo xe tốt\nGiải thích mở rộng: Trong thư khen ngày 13/4/1967, Bác dặn các đồng chí chớ vì thắng lợi mà chủ quan; phải ra sức học tập chính trị, quân sự, kỹ thuật; giữ gìn xe tốt, pháo tốt và tiếp tục lập nhiều chiến công hơn nữa.\nÝ nghĩa: Lời dặn này vừa có giá trị giáo dục tư tưởng, vừa nhấn mạnh yêu cầu chính quy, kỷ luật, làm chủ kỹ thuật của lực lượng pháo binh."},{"num":31,"question":"Năm 1979, bộ đội pháo binh đã chi viện cho lực lượng vũ trang nhân dân trong nhiệm vụ gì?","options":{"A":"Xây dựng vùng kinh tế mới","B":"Bảo vệ biên giới và chủ quyền Tổ quốc","C":"Làm nhiệm vụ cứu trợ thiên tai là chủ yếu","D":"Huấn luyện đối ngoại"},"answer":"B","explanation":"Bảo vệ biên giới và chủ quyền Tổ quốc\nGiải thích mở rộng: Năm 1979, pháo binh đã chi viện cho các lực lượng vũ trang nhân dân chiến đấu, góp phần bảo vệ toàn vẹn lãnh thổ và chủ quyền của Tổ quốc Việt Nam xã hội chủ nghĩa. Đây là giai đoạn lực lượng tiếp tục phát huy vai trò sau ngày đất nước thống nhất.\nÝ nghĩa: Câu hỏi giúp nhận thức rằng sau 1975, pháo binh vẫn tiếp tục trực tiếp làm nhiệm vụ chiến đấu, không chỉ chuyển sang xây dựng đơn thuần."},{"num":32,"question":"Cuối năm 1987, mỗi đơn vị pháo binh dự bị gọi vào huấn luyện mấy tiểu đoàn và mấy đại đội quân dự bị động viên?","options":{"A":"1 tiểu đoàn, 1 đại đội","B":"2 tiểu đoàn, 2 đại đội","C":"3 tiểu đoàn, 1 đại đội","D":"2 tiểu đoàn, 4 đại đội"},"answer":"B","explanation":"2 tiểu đoàn, 2 đại đội\nGiải thích mở rộng: Tài liệu nêu rõ cuối năm 1987, mỗi đơn vị pháo binh dự bị gọi vào huấn luyện 2 tiểu đoàn và 2 đại đội quân dự bị động viên. Đây là biểu hiện của việc quan tâm xây dựng lực lượng dự bị trong điều kiện mới.\nÝ nghĩa: Việc huấn luyện lực lượng dự bị giúp duy trì tiềm lực huy động, sẵn sàng mở rộng lực lượng khi có chiến tranh hoặc tình huống khẩn cấp."},{"num":33,"question":"Ngày 30/6/1988, Bộ Quốc phòng quyết định điều chỉnh các quân đoàn nào từ tuyến trước về tuyến sau?","options":{"A":"1, 2, 3","B":"26, 29, 14","C":"4, 5, 6","D":"7, 9, 13"},"answer":"B","explanation":"26, 29, 14\nGiải thích mở rộng: Ngày 30/6/1988, Bộ Quốc phòng quyết định điều chỉnh Quân đoàn 26, Quân đoàn 29 và Quân đoàn 14 ở tuyến trước về tuyến sau. Cùng với đó, nhiều đơn vị pháo binh được điều chỉnh vị trí đóng quân trên các địa bàn chiến lược.\nÝ nghĩa: Đây là minh chứng cho sự cơ động, tổ chức lại lực lượng pháo binh để phù hợp với yêu cầu nhiệm vụ bảo vệ Tổ quốc trong bối cảnh mới."},{"num":34,"question":"Tháng 8/1989, Bộ Tư lệnh Pháo binh cử Tiểu đoàn 1 của trung đoàn nào sang giúp bạn Campuchia?","options":{"A":"Trung đoàn 45","B":"Trung đoàn 204","C":"Trung đoàn 675","D":"Trung đoàn 208"},"answer":"B","explanation":"Trung đoàn 204\nGiải thích mở rộng: Tháng 8/1989, Tiểu đoàn 1 pháo BM-21 của Trung đoàn 204 cùng 24 đồng chí được cử sang Campuchia giúp bạn huấn luyện và trực tiếp chiến đấu. Lực lượng hoàn thành tốt nhiệm vụ quốc tế được giao.\nÝ nghĩa: Sự kiện này thể hiện tinh thần đoàn kết quốc tế trong sáng của bộ đội pháo binh, đồng thời cho thấy khả năng làm nhiệm vụ xa, nhanh và hiệu quả."},{"num":35,"question":"Từ năm 1991 đến 1995, Hội đồng khoa học cấp Binh chủng và cấp Bộ Quốc phòng đã nghiệm thu bao nhiêu đề tài khoa học quân sự?","options":{"A":"23","B":"36","C":"49","D":"21"},"answer":"B","explanation":"36\nGiải thích mở rộng: Tài liệu nêu rõ trong giai đoạn 1991-1995, Hội đồng khoa học cấp Binh chủng và cấp Bộ Quốc phòng nghiệm thu 36 đề tài khoa học quân sự, cùng với 49 đề tài khoa học kỹ thuật quân sự và nhiều sáng kiến khác.\nÝ nghĩa: Con số này cho thấy pháo binh rất coi trọng nghiên cứu khoa học, tổng kết thực tiễn và đổi mới công nghệ để nâng cao sức mạnh chiến đấu."},{"num":36,"question":"Năm 1996, nhân kỷ niệm 50 năm Ngày truyền thống Pháo binh Việt Nam, có mấy lữ đoàn đạt tiêu chuẩn đơn vị vững mạnh toàn diện?","options":{"A":"2","B":"3","C":"4","D":"5"},"answer":"C","explanation":"4\nGiải thích mở rộng: Tài liệu ghi rõ năm 1996, có 4 lữ đoàn đạt tiêu chuẩn đơn vị vững mạnh toàn diện là 45, 490, 675 và 204. Đây là kết quả nổi bật của phong trào thi đua trên tất cả các mặt công tác.\nÝ nghĩa: Điều đó phản ánh nỗ lực giữ vững chất lượng tổng hợp và sức mạnh chiến đấu của các đơn vị pháo binh trong thời kỳ đổi mới."},{"num":37,"question":"Lữ đoàn 96 được thành lập theo quyết định của Bộ Quốc phòng vào thời gian nào?","options":{"A":"20/8/2008","B":"02/3/2010","C":"27/02/2015","D":"22/4/2006"},"answer":"A","explanation":"20/8/2008\nGiải thích mở rộng: Theo tài liệu, Lữ đoàn 96 được thành lập theo Quyết định số 248/QĐ-BQP ngày 20/8/2008 của Bộ Quốc phòng. Đây là một bước chấn chỉnh tổ chức, biên chế lực lượng trong giai đoạn mới.\nÝ nghĩa: Mốc này cho thấy Bộ Tư lệnh luôn được củng cố, sắp xếp phù hợp để nâng cao khả năng cơ động và đáp ứng nhiệm vụ trong điều kiện hiện đại hóa quân đội."},{"num":38,"question":"Lữ đoàn 675 được chấn chỉnh thành khung thường trực theo quyết định ngày nào?","options":{"A":"20/8/2008","B":"02/3/2010","C":"27/02/2015","D":"16/3/2001"},"answer":"B","explanation":"02/3/2010\nGiải thích mở rộng: Ngày 02/3/2010, Tổng Tham mưu trưởng ban hành quyết định chấn chỉnh Lữ đoàn 675 thành khung thường trực và bảo quản trang bị thời bình. Đây là nội dung quan trọng trong sắp xếp lại tổ chức lực lượng.\nÝ nghĩa: Câu hỏi nhấn mạnh việc tổ chức, biên chế luôn được điều chỉnh linh hoạt để vừa tiết kiệm, vừa giữ được năng lực sẵn sàng chiến đấu."},{"num":39,"question":"Ngày 27/02/2015, đơn vị nào được thành lập trực thuộc Binh chủng Pháo binh?","options":{"A":"Trung tâm Huấn luyện - Đào tạo","B":"Trường Sĩ quan Phòng không","C":"Kho K380","D":"Đảng bộ Binh chủng"},"answer":"A","explanation":"Trung tâm Huấn luyện - Đào tạo\nGiải thích mở rộng: Ngày 27/02/2015, Bộ Quốc phòng ra quyết định thành lập Trung tâm Huấn luyện - Đào tạo trực thuộc Binh chủng Pháo binh trên cơ sở sắp xếp lại một số đầu mối. Đây là bước kiện toàn rất quan trọng về huấn luyện, đào tạo.\nÝ nghĩa: Mốc này phản ánh yêu cầu nâng cao chất lượng nhân lực, huấn luyện chuyên sâu và làm chủ vũ khí trang bị trong tình hình mới."},{"num":40,"question":"Tám chữ vàng truyền thống của Bộ đội Pháo binh - Tên lửa là gì?","options":{"A":"Đoàn kết, cơ động, bí mật, bất ngờ","B":"Chân đồng vai sắt, đánh giỏi, bắn trúng","C":"Quyết chiến, quyết thắng, trung thành, sáng tạo","D":"Giữ tốt, dùng bền, an toàn, tiết kiệm"},"answer":"B","explanation":"Chân đồng vai sắt, đánh giỏi, bắn trúng\nGiải thích mở rộng: Tám chữ vàng “Chân đồng vai sắt, đánh giỏi, bắn trúng” do Bác Hồ khen tặng ngày 13/4/1967 đã trở thành biểu tượng truyền thống của bộ đội pháo binh. Nội dung đó vừa phản ánh bản lĩnh, vừa phản ánh năng lực chuyên môn và nghệ thuật chiến đấu.\nÝ nghĩa: Đây là hạt nhân tinh thần để giáo dục truyền thống, xây dựng ý chí quyết tâm và chuẩn mực phấn đấu cho các thế hệ cán bộ, chiến sĩ."},{"num":41,"question":"Nội dung nào sau đây thuộc nét truyền thống đầu tiên của Bộ đội Pháo binh - Tên lửa?","options":{"A":"Đoàn kết hiệp đồng, lập công tập thể","B":"Không ngừng học tập, rèn luyện làm chủ khoa học kỹ thuật","C":"Luôn trung thành vô hạn với Tổ quốc, với Đảng, với Nhân dân","D":"Tự lực, tự cường, cần kiệm xây dựng đơn vị"},"answer":"C","explanation":"Luôn trung thành vô hạn với Tổ quốc, với Đảng, với Nhân dân\nGiải thích mở rộng: Theo đề cương, nét truyền thống đầu tiên của bộ đội pháo binh - tên lửa là luôn trung thành vô hạn với Tổ quốc Việt Nam xã hội chủ nghĩa, với Đảng, với Nhân dân. Đây là cội nguồn tinh thần của mọi chiến công và trưởng thành.\nÝ nghĩa: Câu hỏi giúp nhận thức đúng nền tảng chính trị - tư tưởng của lực lượng, bởi sức mạnh quân sự trước hết phải được xây trên nền tảng chính trị vững chắc."},{"num":42,"question":"Nội dung nào sau đây thuộc nét truyền thống thứ hai của Bộ đội Pháo binh - Tên lửa?","options":{"A":"Dũng cảm mưu trí sáng tạo nhiều cách đánh hay, càng đánh càng mạnh, càng trưởng thành","B":"Gắn bó máu thịt với nhân dân","C":"Tự lực, tự cường, cần kiệm xây dựng đơn vị","D":"Làm chủ hoàn toàn không gian mạng"},"answer":"A","explanation":"Dũng cảm mưu trí sáng tạo nhiều cách đánh hay, càng đánh càng mạnh, càng trưởng thành\nGiải thích mở rộng: Nét truyền thống thứ hai của bộ đội pháo binh nhấn mạnh sự dũng cảm, mưu trí và sáng tạo nhiều cách đánh hay, qua đó càng chiến đấu càng trưởng thành. Từ Sông Lô đến Điện Biên Phủ, Mậu Thân, 1972 và 1975, điều đó được chứng minh rất rõ.\nÝ nghĩa: Ý nghĩa của truyền thống này là khơi dậy tinh thần sáng tạo trong chiến đấu, không rập khuôn, luôn tìm cách đánh phù hợp để giành thắng lợi."},{"num":43,"question":"Nội dung nào sau đây thuộc nét truyền thống thứ ba của Bộ đội Pháo binh - Tên lửa?","options":{"A":"Đoàn kết hiệp đồng, lập công tập thể, nêu cao tính kỷ luật tự giác nghiêm minh","B":"Giỏi dân vận, mạnh kinh tế","C":"Chỉ ưu tiên tác chiến độc lập","D":"Bảo đảm kỹ thuật là chính"},"answer":"A","explanation":"Đoàn kết hiệp đồng, lập công tập thể, nêu cao tính kỷ luật tự giác nghiêm minh\nGiải thích mở rộng: Đề cương xác định nét truyền thống thứ ba là đoàn kết hiệp đồng, lập công tập thể, nêu cao tính kỷ luật tự giác nghiêm minh. Pháo binh là lực lượng kỹ thuật, tác chiến hiệp đồng cao nên yếu tố tổ chức, kỷ luật đặc biệt quan trọng.\nÝ nghĩa: Điều này nhắc nhở mọi cán bộ, chiến sĩ phải coi trọng tập thể, hiệp đồng chặt chẽ, chấp hành nghiêm để phát huy đầy đủ sức mạnh hỏa lực."},{"num":44,"question":"Nét truyền thống thứ tư của Bộ đội Pháo binh - Tên lửa là gì?","options":{"A":"Chủ động mở rộng hợp tác quốc tế","B":"Không ngừng học tập, rèn luyện vươn lên làm chủ khoa học kỹ thuật quân sự","C":"Cơ động phân tán lực lượng","D":"Tập trung pháo xe kéo là chủ yếu"},"answer":"B","explanation":"Không ngừng học tập, rèn luyện vươn lên làm chủ khoa học kỹ thuật quân sự\nGiải thích mở rộng: Theo tài liệu, nét truyền thống thứ tư là không ngừng học tập, rèn luyện, vươn lên làm chủ khoa học kỹ thuật quân sự. Với binh chủng kỹ thuật như pháo binh - tên lửa, đây là điều kiện để khai thác hiệu quả vũ khí, khí tài.\nÝ nghĩa: Ý nghĩa thực tiễn là cán bộ, chiến sĩ phải giỏi cả bản lĩnh chính trị lẫn chuyên môn kỹ thuật thì mới có thể đánh giỏi, bắn trúng trong điều kiện hiện đại."},{"num":45,"question":"Nét truyền thống thứ năm của Bộ đội Pháo binh - Tên lửa là gì?","options":{"A":"Tự lực, tự cường, cần kiệm xây dựng đơn vị, yêu quý giữ gìn và khai thác tốt vũ khí trang bị","B":"Lấy công nghệ nước ngoài làm nền tảng duy nhất","C":"Tập trung kinh tế là trọng tâm","D":"Chỉ chú trọng huấn luyện dã ngoại"},"answer":"A","explanation":"Tự lực, tự cường, cần kiệm xây dựng đơn vị, yêu quý giữ gìn và khai thác tốt vũ khí trang bị\nGiải thích mở rộng: Nét truyền thống thứ năm nhấn mạnh tự lực, tự cường, cần kiệm xây dựng đơn vị, yêu quý giữ gìn bảo quản và khai thác tốt vũ khí, khí tài, trang bị. Truyền thống này hình thành từ thời đầu rất thiếu thốn về pháo, đạn, khí tài.\nÝ nghĩa: Đây là yêu cầu vừa mang tính đạo đức quân nhân, vừa mang tính kỹ thuật, bảo đảm cho lực lượng luôn có khả năng sẵn sàng chiến đấu cao."},{"num":46,"question":"Nét truyền thống thứ sáu của Bộ đội Pháo binh - Tên lửa là gì?","options":{"A":"Gắn bó máu thịt với nhân dân, với đơn vị bạn, nêu cao tinh thần đoàn kết quốc tế","B":"Ưu tiên tách biệt với địa phương","C":"Chỉ tập trung nhiệm vụ hậu cần","D":"Phát triển kinh tế quốc phòng là chính"},"answer":"A","explanation":"Gắn bó máu thịt với nhân dân, với đơn vị bạn, nêu cao tinh thần đoàn kết quốc tế\nGiải thích mở rộng: Nét truyền thống thứ sáu là gắn bó máu thịt với nhân dân, với đơn vị bạn, nêu cao tinh thần đoàn kết quốc tế. Bộ đội pháo binh vừa là đội quân chiến đấu, vừa là đội quân công tác, gắn bó mật thiết với nhân dân và đồng đội.\nÝ nghĩa: Truyền thống này làm sâu sắc phẩm chất Bộ đội Cụ Hồ, tạo nên điểm tựa chính trị, tinh thần và hậu phương vững chắc cho mọi nhiệm vụ."},{"num":47,"question":"Câu nói của Bác Hồ với Đại đoàn 351 đầu xuân 1953 nhấn mạnh nội dung nào?","options":{"A":"Muốn bắn giỏi phải có tinh thần","B":"Muốn bắt cọp phải vào hang cọp","C":"Muốn bắt cọp thì phải vào hang, muốn thắng địch thì phải có pháo binh","D":"Muốn thắng nhanh thì phải đánh lớn"},"answer":"C","explanation":"Muốn bắt cọp thì phải vào hang, muốn thắng địch thì phải có pháo binh\nGiải thích mở rộng: Đầu xuân 1953, khi tới thăm Đại đoàn 351, Bác Hồ căn dặn: muốn bắt cọp phải vào hang cọp, muốn thắng địch phải có pháo binh. Lời dạy của Bác đã trở thành tư tưởng chỉ đạo tác chiến và xây dựng lực lượng pháo binh.\nÝ nghĩa: Câu nói thể hiện Bác đánh giá rất cao vai trò của pháo binh trong chiến tranh hiện đại, đồng thời khích lệ bộ đội quyết tâm làm chủ hỏa lực."},{"num":48,"question":"Anh hùng nào của Trung đoàn 675 nổi bật với 36 ngày đêm trụ vững trên đồi E ở Điện Biên Phủ?","options":{"A":"Bùi Đình Cầu","B":"Phùng Văn Khầu","C":"Vi Văn Vinh","D":"Trịnh Thế Xương"},"answer":"B","explanation":"Phùng Văn Khầu\nGiải thích mở rộng: Phùng Văn Khầu là tấm gương tiêu biểu của tinh thần chiến đấu ngoan cường trong Chiến dịch Điện Biên Phủ, 36 ngày đêm trụ vững trên đồi E, dù bị thương vẫn kiên cường chiến đấu. Tên tuổi đồng chí gắn với truyền thống anh hùng của Trung đoàn 675.\nÝ nghĩa: Những tấm gương như vậy có giá trị giáo dục sâu sắc về ý chí, bản lĩnh và tinh thần quyết chiến quyết thắng của bộ đội pháo binh."},{"num":49,"question":"Đơn vị nào được Bác Hồ khen tặng danh hiệu “Đoàn Pháo binh Anh dũng”?","options":{"A":"Trung đoàn 45","B":"Trung đoàn 675","C":"Lữ đoàn 490","D":"Trung đoàn 204"},"answer":"B","explanation":"Trung đoàn 675\nGiải thích mở rộng: Trung đoàn 675 là trung đoàn sơn pháo đầu tiên của Binh chủng và được Bác Hồ khen tặng danh hiệu “Đoàn Pháo binh Anh dũng”. Đơn vị lập nhiều chiến công lớn trong kháng chiến chống Pháp và chống Mỹ.\nÝ nghĩa: Danh hiệu ấy vừa là vinh dự, vừa là lời nhắc nhở trách nhiệm giữ gìn và phát huy truyền thống anh hùng của đơn vị."},{"num":50,"question":"Đơn vị nào được Bác Hồ khen tặng danh hiệu “Trung đoàn Tất Thắng”?","options":{"A":"Trung đoàn 675","B":"Trung đoàn 45","C":"Trung đoàn 208","D":"Trung đoàn 96"},"answer":"B","explanation":"Trung đoàn 45\nGiải thích mở rộng: Trung đoàn 45 là trung đoàn pháo xe kéo đầu tiên của Quân đội ta và được Bác Hồ khen tặng danh hiệu “Trung đoàn Tất Thắng”. Đơn vị nổi bật với chiến công kéo pháo vào, kéo pháo ra ở Điện Biên Phủ.\nÝ nghĩa: Câu hỏi góp phần giáo dục niềm tự hào truyền thống, tinh thần quyết thắng và ý chí vượt khó của pháo binh cơ giới đầu tiên."},{"num":51,"question":"Ngày 31/3/1959, Bác Hồ đến thăm đơn vị pháo binh nào?","options":{"A":"Đại đội Pháo binh 34 phòng thủ đảo Hòn Rồng","B":"Trung đoàn 208 tại Vĩnh Yên","C":"Đoàn Pháo binh 374","D":"Đại đoàn 351 ở Bằng Luân"},"answer":"A","explanation":"Đại đội Pháo binh 34 phòng thủ đảo Hòn Rồng\nGiải thích mở rộng: Ngày 31/3/1959, Bác Hồ đến thăm Đại đội Pháo binh 34 làm nhiệm vụ phòng thủ đảo Hòn Rồng, Quảng Ninh. Đây là một trong những sự kiện thiêng liêng thể hiện sự quan tâm sâu sắc của Bác với bộ đội pháo binh.\nÝ nghĩa: Những chuyến thăm của Bác vừa là nguồn cổ vũ tinh thần to lớn, vừa thể hiện sự chăm lo trực tiếp đối với các lực lượng đang làm nhiệm vụ khó khăn, gian khổ."},{"num":52,"question":"Ngày 19/8/1962, Bác Hồ đến thăm đoàn pháo binh nào?","options":{"A":"Đoàn 675","B":"Đoàn 45","C":"Đoàn 374","D":"Đoàn 490"},"answer":"C","explanation":"Đoàn 374\nGiải thích mở rộng: Ngày 19/8/1962, Bác Hồ đến thăm Đoàn Pháo binh 374 và căn dặn cán bộ, chiến sĩ phải luôn luôn sẵn sàng chiến đấu bảo vệ cách mạng, bảo vệ Tổ quốc. Đây là lời dặn chứa đựng yêu cầu rất cao về sẵn sàng chiến đấu.\nÝ nghĩa: Nội dung đó vẫn còn nguyên giá trị trong xây dựng chính quy, duy trì trực sẵn sàng chiến đấu của pháo binh hiện nay."},{"num":53,"question":"Ngày 14/11/1964, Bác Hồ gửi thư khen ngợi lực lượng nào sau chiến công ngày 31/10/1964?","options":{"A":"Quân và dân miền Nam","B":"Quân và dân miền Bắc","C":"Bộ đội pháo binh miền Đông Nam Bộ","D":"Bộ đội tên lửa chiến thuật"},"answer":"B","explanation":"Quân và dân miền Bắc\nGiải thích mở rộng: Ngày 14/11/1964, Bác Hồ gửi thư khen ngợi quân và dân miền Bắc sau chiến công ngày 31/10/1964; đồng thời viết bài “Hoan hô chiến sĩ Biên Hòa” đăng báo Nhân dân với bút danh “Chiến sĩ”. Bối cảnh này gắn với khí thế chống chiến tranh phá hoại của Mỹ.\nÝ nghĩa: Câu hỏi giúp thấy rõ sự cổ vũ, động viên kịp thời của Bác đối với các lực lượng chiến đấu, trong đó có pháo binh."},{"num":54,"question":"Ngày 17/4/1966, Bác Hồ cùng các đồng chí lãnh đạo đến xem loại vũ khí nào do Bộ Tư lệnh Pháo binh cải tiến?","options":{"A":"A12 và ĐKB","B":"BM-21 và Scud-B","C":"D20 và H12","D":"Cối 82 và cối 120"},"answer":"A","explanation":"A12 và ĐKB\nGiải thích mở rộng: Ngày 17/4/1966, Bác Hồ cùng các đồng chí Trường Chinh, Phạm Văn Đồng và Võ Nguyên Giáp đến xem loại hỏa tiễn mang vác A12 do Bộ Tư lệnh Pháo binh cải tiến và ĐKB tại Trường bắn Hòa Lạc. Điều đó cho thấy sự quan tâm của lãnh đạo Đảng, Nhà nước đối với sáng kiến kỹ thuật của pháo binh.\nÝ nghĩa: Sự kiện phản ánh truyền thống chủ động nghiên cứu, cải tiến, phát huy sáng kiến của pháo binh trong điều kiện chiến tranh."},{"num":55,"question":"Đầu năm 1969, Bác Hồ gặp mặt và tặng hoa, huy hiệu cho lực lượng nào của pháo binh?","options":{"A":"3 chiến sĩ bắn máy bay Mỹ","B":"3 chiến sĩ hải pháo bắn cháy, bắn chìm tàu chiến Mỹ ở vùng biển Quảng Bình","C":"3 chiến sĩ kéo pháo ở Điện Biên Phủ","D":"3 cán bộ nghiên cứu khoa học"},"answer":"B","explanation":"3 chiến sĩ hải pháo bắn cháy, bắn chìm tàu chiến Mỹ ở vùng biển Quảng Bình\nGiải thích mở rộng: Đầu năm 1969, Bác Hồ gặp mặt, tặng hoa và huy hiệu cho ba chiến sĩ hải pháo sau khi đơn vị lập chiến công bắn cháy, bắn chìm tàu chiến Mỹ ở vùng biển Quảng Bình. Đây là niềm vinh dự rất lớn đối với bộ đội pháo binh.\nÝ nghĩa: Câu hỏi góp phần làm rõ truyền thống chiến đấu đa dạng của pháo binh trên nhiều môi trường tác chiến khác nhau."},{"num":56,"question":"Trong truyền thống của bộ đội pháo binh, “đánh giỏi” gắn chặt với yêu cầu nào?","options":{"A":"Bắn trúng","B":"Cơ động nhanh","C":"Giữ bí mật","D":"Đánh lâu dài"},"answer":"A","explanation":"Bắn trúng\nGiải thích mở rộng: Theo đề cương, với bộ đội pháo binh, muốn đánh giỏi thì phải bắn trúng, đúng thời cơ, hiệu suất chiến đấu cao. Do đó, “đánh giỏi” không tách rời trình độ kỹ thuật, chỉ huy, hiệp đồng và khả năng làm chủ vũ khí.\nÝ nghĩa: Nội dung này nhấn mạnh chuẩn mực nghề nghiệp đặc thù của binh chủng kỹ thuật: kết quả chiến đấu phải được thể hiện bằng độ chính xác, hiệu quả và thời cơ."},{"num":57,"question":"Phong trào nào nổi bật trong huấn luyện, học tập làm chủ khoa học kỹ thuật của pháo binh những năm 1954-1964?","options":{"A":"Tiếng hát át tiếng bom","B":"Một người biết, hai người giỏi","C":"Sóng Duyên Hải","D":"Ba sẵn sàng"},"answer":"B","explanation":"Một người biết, hai người giỏi\nGiải thích mở rộng: Tài liệu nêu phong trào “Một người biết, hai người giỏi” là điểm nổi bật trong học tập, huấn luyện của bộ đội pháo binh giai đoạn 1954-1964. Phong trào góp phần lan tỏa kiến thức và nâng cao trình độ cho toàn đơn vị.\nÝ nghĩa: Đây là biểu hiện sinh động của truyền thống học tập, rèn luyện, làm chủ kỹ thuật trong binh chủng pháo binh."},{"num":58,"question":"Trong thời kỳ đổi mới, bộ đội pháo binh đã chủ động thực hiện việc gì để làm chủ khoa học công nghệ mới?","options":{"A":"Chỉ nhập khẩu vũ khí","B":"Tích cực nghiên cứu, ứng dụng khoa học công nghệ, đổi mới huấn luyện","C":"Giảm huấn luyện thực hành","D":"Tách khỏi nhà trường"},"answer":"B","explanation":"Tích cực nghiên cứu, ứng dụng khoa học công nghệ, đổi mới huấn luyện\nGiải thích mở rộng: Đề cương cho thấy trong thời kỳ đổi mới, Bộ Tư lệnh đã tích cực, chủ động nghiên cứu, ứng dụng khoa học công nghệ, đổi mới huấn luyện và tổng kết thực tiễn chiến đấu. Đây là đòi hỏi tất yếu của một binh chủng kỹ thuật.\nÝ nghĩa: Nội dung này giúp liên hệ truyền thống với nhiệm vụ hiện đại hóa lực lượng pháo binh - tên lửa trong điều kiện mới."},{"num":59,"question":"Theo đề cương, Bộ Tư lệnh Pháo binh - Tên lửa và bao nhiêu đơn vị, bao nhiêu cán bộ, chiến sĩ đã được phong tặng danh hiệu Anh hùng LLVTND?","options":{"A":"82 đơn vị, 17 cán bộ chiến sĩ","B":"72 đơn vị, 15 cán bộ chiến sĩ","C":"82 đơn vị, 27 cán bộ chiến sĩ","D":"62 đơn vị, 17 cán bộ chiến sĩ"},"answer":"A","explanation":"82 đơn vị, 17 cán bộ chiến sĩ\nGiải thích mở rộng: Đề cương nêu rõ Bộ Tư lệnh Pháo binh - Tên lửa cùng 82 đơn vị và 17 cán bộ, chiến sĩ đã được phong tặng danh hiệu Anh hùng Lực lượng vũ trang nhân dân. Đây là thành tích đặc biệt vẻ vang của toàn lực lượng.\nÝ nghĩa: Con số này phản ánh quy mô chiến công, sự hy sinh và đóng góp to lớn của các thế hệ bộ đội pháo binh - tên lửa đối với sự nghiệp cách mạng."},{"num":60,"question":"Huân chương Quân công hạng Nhất ghi nhận thành tích xây dựng và chiến đấu từ 1954-1967 được quyết định vào ngày nào?","options":{"A":"08/6/1967","B":"15/7/1968","C":"28/6/1971","D":"03/6/1976"},"answer":"A","explanation":"08/6/1967\nGiải thích mở rộng: Một trong những phần thưởng cao quý của pháo binh là Huân chương Quân công hạng Nhất cho thành tích xây dựng và chiến đấu từ 1954-1967, được quyết định ngày 08/6/1967. Đây là sự ghi nhận của Đảng và Nhà nước đối với những chiến công xuất sắc của lực lượng.\nÝ nghĩa: Phần thưởng giúp khẳng định vị trí, vai trò của pháo binh trong cả xây dựng lực lượng và chiến đấu bảo vệ miền Bắc, chi viện miền Nam."},{"num":61,"question":"Huân chương Quân công giải phóng hạng Nhì của lực lượng pháo binh gắn với thành tích ở mặt trận nào?","options":{"A":"Đường 9 - Khe Sanh 1967-1968","B":"Biên giới 1950","C":"Điện Biên Phủ 1954","D":"Hồ Chí Minh 1975"},"answer":"A","explanation":"Đường 9 - Khe Sanh 1967-1968\nGiải thích mở rộng: Theo danh mục phần thưởng, Huân chương Quân công giải phóng hạng Nhì được khen tặng lực lượng pháo binh vì thành tích trong chiến đấu ở Mặt trận Đường 9 - Khe Sanh 1967-1968. Đây là chiến trường ác liệt, đòi hỏi hỏa lực rất lớn.\nÝ nghĩa: Phần thưởng cho thấy pháo binh đã phát huy mạnh mẽ vai trò trong các chiến dịch quy mô lớn thời kỳ chống Mỹ."},{"num":62,"question":"Huân chương Quân công hạng Nhì được khen tặng lực lượng pháo binh Đường 9 - Nam Lào theo quyết định ngày nào?","options":{"A":"28/6/1971","B":"21/12/1979","C":"20/3/1983","D":"16/3/2001"},"answer":"A","explanation":"28/6/1971\nGiải thích mở rộng: Trong hệ thống phần thưởng, lực lượng pháo binh Đường 9 - Nam Lào được tặng Huân chương Quân công hạng Nhì theo quyết định ngày 28/6/1971. Đây là chiến dịch chứng tỏ sự trưởng thành nhanh của pháo binh trong hiệp đồng tác chiến hiện đại.\nÝ nghĩa: Câu hỏi giúp gắn phần thưởng với chiến công cụ thể, làm nổi bật sự ghi nhận của Nhà nước đối với thành tích chiến đấu xuất sắc."},{"num":63,"question":"Binh chủng Pháo binh được Nhà nước phong tặng danh hiệu Anh hùng LLVTND vào ngày nào?","options":{"A":"22/4/2006","B":"03/6/1976","C":"26/11/2000","D":"21/12/2010"},"answer":"B","explanation":"03/6/1976\nGiải thích mở rộng: Theo đề cương, ngày 03/6/1976 Binh chủng Pháo binh được Nhà nước phong tặng danh hiệu Anh hùng Lực lượng vũ trang nhân dân. Đây là sự ghi nhận rất cao đối với thành tích vẻ vang trong chiến tranh giải phóng dân tộc.\nÝ nghĩa: Danh hiệu Anh hùng là niềm tự hào lớn, đồng thời là trách nhiệm giữ gìn và phát huy truyền thống đối với các thế hệ hôm nay."},{"num":64,"question":"Huân chương Hồ Chí Minh hạng Nhì của Binh chủng Pháo binh gắn với thành tích trong cuộc kháng chiến nào?","options":{"A":"Chống Pháp","B":"Bảo vệ biên giới Tây Nam","C":"Chống Mỹ cứu nước","D":"Đổi mới đất nước"},"answer":"C","explanation":"Chống Mỹ cứu nước\nGiải thích mở rộng: Huân chương Hồ Chí Minh hạng Nhì được trao cho Binh chủng Pháo binh vì thành tích trong cuộc kháng chiến chống Mỹ cứu nước theo quyết định ngày 21/12/1979. Đây là phần thưởng cao quý ghi nhận đóng góp to lớn của lực lượng.\nÝ nghĩa: Điều đó khẳng định pháo binh là một trong những binh chủng có vai trò đặc biệt quan trọng trong đại thắng mùa Xuân 1975."},{"num":65,"question":"Binh chủng Pháo binh được nhận Giải thưởng nào vào ngày 26/11/2000?","options":{"A":"Giải thưởng Hồ Chí Minh","B":"Giải thưởng Sao vàng đất Việt","C":"Giải thưởng Nhà nước về văn học nghệ thuật","D":"Giải thưởng Quân sự ASEAN"},"answer":"A","explanation":"Giải thưởng Hồ Chí Minh\nGiải thích mở rộng: Ngày 26/11/2000, Binh chủng Pháo binh được nhận Giải thưởng Hồ Chí Minh với cụm công trình về nghệ thuật quân sự của bộ đội pháo binh trong cuộc kháng chiến chống Mỹ cứu nước. Đây là sự đánh giá rất cao đối với giá trị lý luận và thực tiễn của kinh nghiệm chiến đấu pháo binh.\nÝ nghĩa: Giải thưởng cho thấy truyền thống pháo binh không chỉ ở chiến công mà còn ở trình độ tổng kết, phát triển nghệ thuật quân sự Việt Nam."},{"num":66,"question":"Huân chương Độc lập hạng Nhất của Binh chủng Pháo binh được trao cho thành tích giai đoạn nào?","options":{"A":"1946-1954","B":"1965-1975","C":"1990-2000","D":"2005-2010"},"answer":"C","explanation":"1990-2000\nGiải thích mở rộng: Huân chương Độc lập hạng Nhất được trao cho Binh chủng Pháo binh vì thành tích xuất sắc trong thời kỳ đổi mới 1990-2000 theo quyết định ngày 16/3/2001. Điều đó cho thấy lực lượng không chỉ mạnh trong chiến tranh mà còn vững vàng trong xây dựng hòa bình.\nÝ nghĩa: Phần thưởng phản ánh kết quả toàn diện của binh chủng trong huấn luyện, sẵn sàng chiến đấu, xây dựng chính quy và đổi mới."},{"num":67,"question":"Phần thưởng cao quý nhất của Đảng và Nhà nước mà Binh chủng Pháo binh được nhận năm 2006 là gì?","options":{"A":"Huân chương Hồ Chí Minh","B":"Huân chương Độc lập hạng Nhất","C":"Huân chương Sao vàng","D":"Huân chương Quân công hạng Nhất"},"answer":"C","explanation":"Huân chương Sao vàng\nGiải thích mở rộng: Theo đề cương, Binh chủng Pháo binh được tặng Huân chương Sao vàng theo quyết định ngày 22/4/2006. Đây là phần thưởng cao quý nhất của Đảng và Nhà nước dành cho tập thể có công lao đặc biệt xuất sắc.\nÝ nghĩa: Phần thưởng khẳng định tầm vóc lịch sử, truyền thống và đóng góp đặc biệt to lớn của bộ đội pháo binh - tên lửa trong suốt chặng đường cách mạng."},{"num":68,"question":"Năm 2010, Binh chủng Pháo binh được tặng phần thưởng nào vì thành tích xuất sắc trong 5 năm 2005-2010?","options":{"A":"Huân chương Quân công hạng Nhất","B":"Huân chương Lao động hạng Nhất","C":"Huân chương Chiến công hạng Nhất","D":"Huân chương Bảo vệ Tổ quốc hạng Nhất"},"answer":"A","explanation":"Huân chương Quân công hạng Nhất\nGiải thích mở rộng: Ngày 21/12/2010, Binh chủng Pháo binh được tặng Huân chương Quân công hạng Nhất vì thành tích xuất sắc trong 5 năm 2005-2010. Đây là phần thưởng tiếp nối chuỗi thành tích nổi bật trong thời kỳ đẩy mạnh xây dựng lực lượng chính quy, từng bước hiện đại.\nÝ nghĩa: Phần thưởng thể hiện sự ghi nhận của Đảng, Nhà nước đối với kết quả phấn đấu toàn diện của binh chủng trong giai đoạn mới."},{"num":69,"question":"Nhà nước Campuchia tặng Huy chương Hữu nghị hạng Thập-Ba-Đân cho Binh chủng Pháo binh vào năm nào?","options":{"A":"2008","B":"2010","C":"2014","D":"2016"},"answer":"C","explanation":"2014\nGiải thích mở rộng: Theo đề cương, năm 2014 Binh chủng Pháo binh được Nhà nước Căm-pu-chia tặng Huy chương Hữu nghị hạng Thập-Ba-Đân. Đây là sự ghi nhận đối với những đóng góp và tình đoàn kết quốc tế của lực lượng.\nÝ nghĩa: Phần thưởng làm nổi bật truyền thống đoàn kết quốc tế, nghĩa tình, thủy chung của bộ đội pháo binh với bạn bè quốc tế."},{"num":70,"question":"Trong kháng chiến chống Pháp, bộ đội pháo binh được tặng bao nhiêu Huân chương Quân công?","options":{"A":"15","B":"25","C":"35","D":"45"},"answer":"B","explanation":"25\nGiải thích mở rộng: Đề cương nêu rõ sau cuộc kháng chiến chống thực dân Pháp thắng lợi, bộ đội pháo binh vinh dự được tặng thưởng 25 Huân chương Quân công. Đây là phần thưởng xứng đáng cho những chiến công xuất sắc của lực lượng còn non trẻ nhưng rất anh hùng.\nÝ nghĩa: Con số này cho thấy ngay từ buổi đầu, pháo binh đã lập được nhiều chiến công lớn, góp phần quyết định vào thắng lợi của kháng chiến."},{"num":71,"question":"Trong kháng chiến chống Pháp, bộ đội pháo binh được tặng bao nhiêu Huân chương Chiến công?","options":{"A":"394","B":"494","C":"594","D":"694"},"answer":"C","explanation":"594\nGiải thích mở rộng: Theo đề cương, bộ đội pháo binh được tặng 594 Huân chương Chiến công sau thắng lợi của cuộc kháng chiến chống thực dân Pháp. Đây là sự ghi nhận rộng khắp đối với nhiều tập thể, cá nhân lập công xuất sắc.\nÝ nghĩa: Thành tích đó phản ánh mức độ đóng góp rất sâu rộng của pháo binh trên nhiều chiến trường và nhiều hình thức chiến đấu."},{"num":72,"question":"Liệt sĩ Trịnh Thế Xương được Nhà nước truy tặng danh hiệu Anh hùng LLVTND vào ngày nào?","options":{"A":"28/4/2000","B":"03/6/1976","C":"12/12/2000","D":"31/12/1973"},"answer":"A","explanation":"28/4/2000\nGiải thích mở rộng: Ngày 28/4/2000, liệt sĩ Trịnh Thế Xương, nguyên là Khẩu đội trưởng của Trung đoàn 675, được Nhà nước truy tặng danh hiệu Anh hùng Lực lượng vũ trang nhân dân. Đây là sự tôn vinh xứng đáng đối với tấm gương chiến đấu anh dũng của đồng chí.\nÝ nghĩa: Việc tôn vinh các anh hùng giúp giữ gìn ký ức lịch sử, giáo dục truyền thống và bồi đắp lý tưởng cho thế hệ trẻ hôm nay."},{"num":73,"question":"Theo truyền thống của pháo binh, khẩu hiệu “Đâu cần Pháo binh có, khó mấy Pháo binh cũng vượt qua” thể hiện rõ nhất nội dung nào?","options":{"A":"Tự lực, tự cường và tinh thần trách nhiệm cao","B":"Chỉ đạo tác chiến độc lập","C":"Mở rộng đối ngoại quân sự","D":"Ưu tiên kinh tế quốc phòng"},"answer":"A","explanation":"Tự lực, tự cường và tinh thần trách nhiệm cao\nGiải thích mở rộng: Khẩu hiệu này gắn với phẩm chất trung thành, trách nhiệm, tinh thần vượt khó và quyết tâm hoàn thành mọi nhiệm vụ của bộ đội pháo binh. Nó thể hiện sâu sắc ý chí phục vụ chiến đấu trong mọi hoàn cảnh.\nÝ nghĩa: Ý nghĩa của khẩu hiệu là cổ vũ cán bộ, chiến sĩ chủ động nhận việc khó, việc nặng, giữ vững bản lĩnh và lòng trung thành trong mọi tình huống."},{"num":74,"question":"Trong truyền thống pháo binh, “đoàn kết hiệp đồng, lập công tập thể” gắn với yêu cầu đặc thù nào của binh chủng?","options":{"A":"Tác chiến đơn độc là chính","B":"Là hỏa lực chủ yếu mặt đất, hiệp đồng cao","C":"Hoạt động chỉ trên biển","D":"Chuyên làm nhiệm vụ hậu cần"},"answer":"B","explanation":"Là hỏa lực chủ yếu mặt đất, hiệp đồng cao\nGiải thích mở rộng: Pháo binh là hỏa lực chủ yếu mặt đất, có tính hiệp đồng rất cao giữa trinh sát, chỉ huy, phần tử bắn, cơ động, kỹ thuật, bảo đảm. Vì vậy truyền thống đoàn kết hiệp đồng, lập công tập thể là yêu cầu mang tính sống còn.\nÝ nghĩa: Điều này nhấn mạnh rằng sức mạnh pháo binh không chỉ ở vũ khí mà còn ở tổ chức, kỷ luật và sự phối hợp thống nhất của tập thể."},{"num":75,"question":"Trong truyền thống thứ năm, vì sao bộ đội pháo binh đặc biệt coi trọng việc giữ tốt, dùng bền vũ khí trang bị?","options":{"A":"Vì pháo binh không cần huấn luyện nhiều","B":"Vì đây là binh chủng kỹ thuật, hiệu quả chiến đấu phụ thuộc lớn vào trạng thái kỹ thuật","C":"Vì chủ yếu dùng vũ khí thu được","D":"Vì chỉ làm nhiệm vụ thời bình"},"answer":"B","explanation":"Vì đây là binh chủng kỹ thuật, hiệu quả chiến đấu phụ thuộc lớn vào trạng thái kỹ thuật\nGiải thích mở rộng: Pháo binh - tên lửa là binh chủng kỹ thuật, nên trạng thái kỹ thuật của pháo, xe, đạn, khí tài quyết định trực tiếp chất lượng huấn luyện và hiệu quả chiến đấu. Từ thời kháng chiến đến hiện nay, giữ tốt - dùng bền luôn là yêu cầu quan trọng.\nÝ nghĩa: Ý nghĩa của truyền thống này là nâng cao ý thức trách nhiệm, tiết kiệm và làm chủ vũ khí trang bị trong toàn lực lượng."},{"num":76,"question":"Trong kháng chiến chống Mỹ, bộ đội pháo binh Tây Nguyên nổi tiếng với truyền thống nào?","options":{"A":"Tự lực, sáng tạo, đánh giỏi, bắn trúng","B":"Huấn luyện giỏi, điều lệnh nghiêm","C":"Hậu cần nhanh, tài chính mạnh","D":"Kỷ luật sắt, cơ động sâu"},"answer":"A","explanation":"Tự lực, sáng tạo, đánh giỏi, bắn trúng\nGiải thích mở rộng: Đề cương nhấn mạnh pháo binh Tây Nguyên gắn bó với chiến trường khó khăn, gian khổ nhưng rất nổi tiếng với truyền thống “Tự lực, sáng tạo, đánh giỏi, bắn trúng”. Đây là nét tiêu biểu của pháo binh trên chiến trường ác liệt này.\nÝ nghĩa: Câu hỏi cho thấy truyền thống chung của binh chủng luôn được cụ thể hóa sinh động ở từng chiến trường, từng đơn vị."},{"num":77,"question":"Pháo binh miền Đông Nam Bộ trong kháng chiến chống Mỹ được nêu bật ở đặc điểm nào?","options":{"A":"Được trang bị đầy đủ ngay từ đầu","B":"Từ tay không vừa chiến đấu, vừa xây dựng lực lượng","C":"Chỉ làm nhiệm vụ phòng thủ","D":"Chủ yếu tiếp nhận chi viện đường biển"},"answer":"B","explanation":"Từ tay không vừa chiến đấu, vừa xây dựng lực lượng\nGiải thích mở rộng: Đề cương nhấn mạnh pháo binh miền Đông Nam Bộ từ tay không vừa chiến đấu, vừa xây dựng lực lượng, suốt nhiều năm liên tục bám trụ và chiến đấu giỏi. Đây là minh chứng sinh động cho ý chí tự lực, tự cường của bộ đội pháo binh.\nÝ nghĩa: Nội dung này có ý nghĩa giáo dục rất cao về tinh thần vượt khó, sáng tạo, bám trụ và phát triển lực lượng trong hoàn cảnh cực kỳ gian khổ."},{"num":78,"question":"Trong truyền thống của bộ đội pháo binh, việc gắn bó máu thịt với nhân dân xuất phát từ nhận thức nào?","options":{"A":"Bộ đội là con em của nhân dân","B":"Pháo binh cần hậu cần dân sự là chủ yếu","C":"Nhân dân trực tiếp chỉ huy pháo binh","D":"Chỉ để làm công tác dân vận"},"answer":"A","explanation":"Bộ đội là con em của nhân dân\nGiải thích mở rộng: Theo đề cương, bộ đội pháo binh là con em của nhân dân, từ nhân dân mà ra, vì nhân dân mà chiến đấu. Vì vậy gắn bó máu thịt với nhân dân là truyền thống tự nhiên, bền vững và rất sâu sắc của lực lượng.\nÝ nghĩa: Điều đó khẳng định cội nguồn sức mạnh của quân đội ta nói chung và pháo binh nói riêng nằm ở lòng dân, thế trận lòng dân."},{"num":79,"question":"Trong thời kỳ đổi mới, phương châm huấn luyện của Bộ Tư lệnh Pháo binh được nhấn mạnh là gì?","options":{"A":"Nhanh, mạnh, chính xác","B":"Cơ bản, thiết thực, vững chắc","C":"Độc lập, bí mật, bất ngờ","D":"Tập trung, thống nhất, dài ngày"},"answer":"B","explanation":"Cơ bản, thiết thực, vững chắc\nGiải thích mở rộng: Đề cương nêu rõ công tác huấn luyện, đào tạo của Binh chủng thực hiện đúng phương châm “cơ bản, thiết thực, vững chắc”, coi trọng huấn luyện đồng bộ, chuyên sâu, sát nhiệm vụ, đối tượng, thực tế chiến đấu và an toàn.\nÝ nghĩa: Phương châm này là cơ sở để nâng cao chất lượng tổng hợp, trình độ sẵn sàng chiến đấu và khả năng làm chủ vũ khí trang bị của bộ đội."},{"num":80,"question":"Trong thời kỳ mới, xây dựng Bộ Tư lệnh Pháo binh - Tên lửa vững mạnh về chính trị nhằm mục tiêu trực tiếp nào?","options":{"A":"Tăng biên chế hành chính","B":"Nâng cao chất lượng tổng hợp, sức mạnh chiến đấu","C":"Chủ yếu phục vụ hội thi","D":"Giảm huấn luyện dã ngoại"},"answer":"B","explanation":"Nâng cao chất lượng tổng hợp, sức mạnh chiến đấu\nGiải thích mở rộng: Phần định hướng của đề cương nhấn mạnh xây dựng Bộ Tư lệnh Pháo binh - Tên lửa vững mạnh về chính trị để nâng cao chất lượng tổng hợp và sức mạnh chiến đấu. Đây là yêu cầu xuyên suốt trong xây dựng quân đội cách mạng.\nÝ nghĩa: Ý nghĩa của nội dung này là đặt yếu tố chính trị làm nền tảng, bảo đảm cho bộ đội giữ vững bản lĩnh, đoàn kết và quyết tâm hoàn thành nhiệm vụ."},{"num":81,"question":"Việc kỷ niệm 80 năm ngày truyền thống Bộ đội Pháo binh - Tên lửa có ý nghĩa trực tiếp nào sau đây?","options":{"A":"Chỉ để tổng kết thành tích","B":"Khơi dậy niềm tự hào, trách nhiệm giữ gìn và phát huy truyền thống","C":"Chỉ nhằm tuyên truyền đối ngoại","D":"Chỉ phục vụ công tác thi đua ngắn hạn"},"answer":"B","explanation":"Khơi dậy niềm tự hào, trách nhiệm giữ gìn và phát huy truyền thống\nGiải thích mở rộng: Theo đề cương, kỷ niệm 80 năm ngày truyền thống là dịp ôn lại lịch sử vẻ vang, khơi dậy niềm tự hào, lòng biết ơn và ý thức trách nhiệm của cán bộ, chiến sĩ trong xây dựng Bộ Tư lệnh Pháo binh - Tên lửa Anh hùng.\nÝ nghĩa: Câu hỏi giúp liên hệ giữa giáo dục truyền thống với hành động thực tiễn hôm nay: học truyền thống để tiếp tục phấn đấu, hoàn thành tốt nhiệm vụ."},{"num":82,"question":"Một trong những yêu cầu lớn hiện nay đối với pháo binh - tên lửa là gì?","options":{"A":"Chỉ duy trì lực lượng cũ","B":"Xây dựng chính quy, nâng cao chất lượng huấn luyện và khả năng làm chủ vũ khí trang bị","C":"Giảm hoàn toàn huấn luyện kỹ thuật","D":"Tách khỏi nhiệm vụ sẵn sàng chiến đấu"},"answer":"B","explanation":"Xây dựng chính quy, nâng cao chất lượng huấn luyện và khả năng làm chủ vũ khí trang bị\nGiải thích mở rộng: Tài liệu nhiều lần nhấn mạnh yêu cầu chấn chỉnh tổ chức, biên chế; nâng cao chất lượng huấn luyện, sẵn sàng chiến đấu và làm chủ vũ khí trang bị trong điều kiện mới. Đây là nhiệm vụ trung tâm của bộ đội pháo binh - tên lửa hiện nay.\nÝ nghĩa: Ý nghĩa là phát huy truyền thống bằng hành động cụ thể: chính quy hơn, tinh nhuệ hơn và từng bước hiện đại hơn."},{"num":83,"question":"Trong quá trình xây dựng lực lượng, bộ đội pháo binh luôn coi trọng sự kết hợp giữa huấn luyện quân sự với nội dung nào?","options":{"A":"Giáo dục chính trị","B":"Tăng gia sản xuất đơn thuần","C":"Giao lưu văn nghệ","D":"Thi đấu thể thao"},"answer":"A","explanation":"Giáo dục chính trị\nGiải thích mở rộng: Theo đề cương, huấn luyện của Binh chủng luôn gắn chặt giữa huấn luyện quân sự với giáo dục chính trị; giữa giáo dục - đào tạo với huấn luyện chiến đấu. Đây là đặc trưng của quân đội cách mạng dưới sự lãnh đạo của Đảng.\nÝ nghĩa: Sự kết hợp đó bảo đảm người chiến sĩ vừa có bản lĩnh chính trị vững vàng, vừa có trình độ chuyên môn kỹ thuật đáp ứng yêu cầu nhiệm vụ."},{"num":84,"question":"Trong truyền thống pháo binh, yếu tố nào giúp 'càng đánh càng mạnh, càng trưởng thành'?","options":{"A":"Luôn tác chiến độc lập","B":"Biết sáng tạo cách đánh, phát huy tính năng động và học từ thực tiễn chiến đấu","C":"Chỉ dựa vào vũ khí hiện đại hơn địch","D":"Đánh ít để giữ lực lượng"},"answer":"B","explanation":"Biết sáng tạo cách đánh, phát huy tính năng động và học từ thực tiễn chiến đấu\nGiải thích mở rộng: Đề cương nhấn mạnh bộ đội pháo binh biết vận dụng tư tưởng quân sự Hồ Chí Minh, phát huy mưu trí, sáng tạo và tính năng động trong chiến đấu. Chính quá trình thực tiễn chiến đấu khốc liệt đã rèn luyện để lực lượng ngày càng trưởng thành.\nÝ nghĩa: Bài học này rất quan trọng trong xây dựng lực lượng hiện nay: phải học từ thực tiễn, từ diễn tập, từ huấn luyện sát chiến trường."},{"num":85,"question":"Trong xây dựng Bộ Tư lệnh hiện nay, việc chăm lo công tác hậu cần, tài chính có mục đích chủ yếu gì?","options":{"A":"Phục vụ đời sống và bảo đảm nhiệm vụ huấn luyện, SSCĐ","B":"Chỉ để cải thiện doanh trại","C":"Chủ yếu cho hoạt động đối ngoại","D":"Để giảm huấn luyện chuyên ngành"},"answer":"A","explanation":"Phục vụ đời sống và bảo đảm nhiệm vụ huấn luyện, SSCĐ\nGiải thích mở rộng: Đề cương khẳng định công tác hậu cần, tài chính phải đáp ứng tốt yêu cầu huấn luyện, sẵn sàng chiến đấu và bảo đảm đời sống bộ đội. Đây là phần bảo đảm nền tảng để bộ đội yên tâm công tác, hoàn thành nhiệm vụ.\nÝ nghĩa: Nội dung này cho thấy xây dựng sức mạnh chiến đấu là tổng hợp nhiều mặt, trong đó bảo đảm hậu cần - tài chính giữ vai trò rất quan trọng."},{"num":86,"question":"Theo đề cương, bộ đội pháo binh - tên lửa là loại lực lượng nào trong Quân đội nhân dân Việt Nam?","options":{"A":"Chỉ là lực lượng dự bị","B":"Binh chủng chiến đấu - binh chủng kỹ thuật","C":"Lực lượng hậu cần chuyên trách","D":"Lực lượng cảnh vệ"},"answer":"B","explanation":"Binh chủng chiến đấu - binh chủng kỹ thuật\nGiải thích mở rộng: Ngay phần truyền thống, đề cương xác định đây là một binh chủng chiến đấu đồng thời là binh chủng kỹ thuật, ra đời sớm và có quá trình trưởng thành gắn với nhiều chiến công lớn. Tính chất này quy định yêu cầu cao về bản lĩnh, kỷ luật và trình độ kỹ thuật.\nÝ nghĩa: Nhận thức đúng đặc trưng của lực lượng sẽ giúp hiểu đúng vai trò của pháo binh - tên lửa trong chiến tranh và trong xây dựng quân đội hiện nay."},{"num":87,"question":"Vai trò nổi bật của pháo binh trong tác chiến hiệp đồng binh chủng được xác định là gì?","options":{"A":"Lực lượng hậu bị chiến dịch","B":"Hỏa lực chủ yếu mặt đất","C":"Lực lượng trinh sát sâu","D":"Lực lượng thông tin cơ động"},"answer":"B","explanation":"Hỏa lực chủ yếu mặt đất\nGiải thích mở rộng: Đề cương nhiều lần xác định pháo binh là hỏa lực chủ yếu mặt đất trong tác chiến hiệp đồng binh chủng. Bởi vậy, chất lượng sử dụng pháo binh có ảnh hưởng trực tiếp đến khả năng tạo ưu thế hỏa lực trên chiến trường.\nÝ nghĩa: Ý nghĩa của nhận thức này là phải coi trọng xây dựng pháo binh về mọi mặt, từ con người, tổ chức đến kỹ thuật, bảo đảm."},{"num":88,"question":"Một trong những giá trị nổi bật của truyền thống pháo binh trong thời kỳ mới là gì?","options":{"A":"Phát huy giá trị văn hóa Bộ đội Cụ Hồ","B":"Tách rời công tác Đảng, công tác chính trị","C":"Giảm giáo dục chính trị tư tưởng","D":"Chỉ quan tâm trang bị mới"},"answer":"A","explanation":"Phát huy giá trị văn hóa Bộ đội Cụ Hồ\nGiải thích mở rộng: Phần nhiệm vụ phát huy truyền thống nhấn mạnh việc tiếp tục phát huy giá trị văn hóa “Bộ đội Cụ Hồ” thời kỳ mới. Đây là nền tảng để xây dựng con người pháo binh có bản lĩnh, đạo đức, lối sống và tác phong công tác tốt.\nÝ nghĩa: Câu hỏi liên hệ trực tiếp giữa truyền thống lịch sử với yêu cầu xây dựng nhân cách quân nhân trong bối cảnh hiện nay."},{"num":89,"question":"Trong thời kỳ đổi mới, việc giúp nhân dân xóa đói giảm nghèo, phát triển kinh tế - xã hội thể hiện rõ truyền thống nào của pháo binh?","options":{"A":"Đánh giỏi, bắn trúng","B":"Tự lực, tự cường","C":"Gắn bó máu thịt với nhân dân","D":"Lập công tập thể"},"answer":"C","explanation":"Gắn bó máu thịt với nhân dân\nGiải thích mở rộng: Đề cương nêu rõ bước vào thời kỳ đổi mới, bộ đội pháo binh - tên lửa đóng quân ở nhiều địa bàn khó khăn, đã tích cực giúp nhân dân xóa đói giảm nghèo, phát triển kinh tế - xã hội. Đây là biểu hiện sinh động của mối quan hệ máu thịt quân - dân.\nÝ nghĩa: Nội dung này khẳng định pháo binh không chỉ mạnh trong chiến đấu mà còn tốt trong công tác dân vận, xứng đáng với hình ảnh Bộ đội Cụ Hồ."},{"num":90,"question":"Cụm từ “vừa đánh, vừa học, vừa làm” trong quá trình xây dựng lực lượng pháo binh phản ánh rõ nhất truyền thống nào?","options":{"A":"Không ngừng học tập, rèn luyện làm chủ khoa học kỹ thuật","B":"Chỉ chiến đấu độc lập","C":"Đoàn kết quốc tế","D":"Bảo đảm hậu cần chủ động"},"answer":"A","explanation":"Không ngừng học tập, rèn luyện làm chủ khoa học kỹ thuật\nGiải thích mở rộng: Trong điều kiện ban đầu rất thiếu thốn, bộ đội pháo binh phải vừa chiến đấu vừa học cách sử dụng, sửa chữa, cải tiến vũ khí. Chính quá trình đó hình thành truyền thống học tập, rèn luyện và làm chủ khoa học kỹ thuật quân sự.\nÝ nghĩa: Đây là bài học còn nguyên giá trị cho hôm nay khi lực lượng tiếp cận những trang bị ngày càng hiện đại, phức tạp hơn."},{"num":91,"question":"Từ nội dung đề cương, có thể hiểu điểm cốt lõi của 'bắn trúng' trong truyền thống pháo binh là gì?","options":{"A":"Bắn nhiều đạn","B":"Bắn đúng mục tiêu, đúng thời cơ, hiệu suất cao","C":"Bắn ở cự ly gần","D":"Bắn trong đêm"},"answer":"B","explanation":"Bắn đúng mục tiêu, đúng thời cơ, hiệu suất cao\nGiải thích mở rộng: “Bắn trúng” không chỉ là trúng mục tiêu về kỹ thuật, mà còn hàm ý đúng thời cơ, đạt hiệu suất chiến đấu cao và phục vụ thắng lợi chung của nhiệm vụ. Nó đòi hỏi tổng hợp từ trinh sát, tính toán phần tử đến hiệp đồng và kỹ thuật bắn.\nÝ nghĩa: Đây là chuẩn mực nghề nghiệp cốt lõi của người lính pháo binh, phản ánh tính khoa học và độ chính xác của hỏa lực pháo binh hiện đại."},{"num":92,"question":"Một nội dung rất quan trọng khi phát huy truyền thống pháo binh trong giai đoạn hiện nay là gì?","options":{"A":"Giảm chấp hành kỷ luật để tăng sáng tạo","B":"Tiếp tục xây dựng tổ chức đảng trong sạch vững mạnh, đơn vị vững mạnh toàn diện","C":"Chỉ tập trung hoạt động phong trào","D":"Tách huấn luyện khỏi thực tế chiến đấu"},"answer":"B","explanation":"Tiếp tục xây dựng tổ chức đảng trong sạch vững mạnh, đơn vị vững mạnh toàn diện\nGiải thích mở rộng: Đề cương dành phần riêng để nhấn mạnh xây dựng Bộ Tư lệnh vững mạnh về chính trị, tổ chức đảng trong sạch vững mạnh, đơn vị vững mạnh toàn diện. Đây là điều kiện quyết định để phát huy truyền thống trong tình hình mới.\nÝ nghĩa: Ý nghĩa là truyền thống không chỉ để tự hào mà phải được chuyển hóa thành chất lượng xây dựng đơn vị và sức mạnh chiến đấu cụ thể."},{"num":93,"question":"Khi học về 80 năm truyền thống Bộ tư lệnh Pháo binh - Tên lửa, yêu cầu phương pháp đúng đắn nhất đối với cán bộ, chiến sĩ là gì?","options":{"A":"Chỉ ghi nhớ mốc năm, tháng","B":"Gắn nhận thức lịch sử với trách nhiệm học tập, rèn luyện, hoàn thành nhiệm vụ hiện nay","C":"Chỉ học thuộc tên đơn vị anh hùng","D":"Tách truyền thống khỏi thực tiễn công tác"},"answer":"B","explanation":"Gắn nhận thức lịch sử với trách nhiệm học tập, rèn luyện, hoàn thành nhiệm vụ hiện nay\nGiải thích mở rộng: Ý nghĩa sâu nhất của giáo dục truyền thống không dừng ở việc nhớ sự kiện, mà phải biến lịch sử thành động lực chính trị tinh thần cho công tác, huấn luyện và sẵn sàng chiến đấu hôm nay. Đó cũng là tinh thần xuyên suốt của đề cương tuyên truyền 80 năm.\nÝ nghĩa: Câu hỏi mang tính tổng kết, định hướng nhận thức và hành động cho người học khi tiếp cận chủ đề truyền thống của lực lượng."},{"num":94,"question":"Ngày 17/3/1954, tại mặt trận Điện Biên Phủ, đơn vị nào vinh dự đón nhận lá cờ Bác tặng về hầm pháo của đơn vị?","options":{"A":"Trung đoàn 675","B":"Đại đội 806, Trung đoàn 45","C":"Đại đội 34 đảo Hòn Rồng","D":"Đoàn 374"},"answer":"B","explanation":"Đại đội 806, Trung đoàn 45\nGiải thích mở rộng: Theo phụ lục về những sự kiện thiêng liêng Bác Hồ với bộ đội pháo binh, ngày 17/3/1954 Đại đội 806 thuộc Trung đoàn 45 vinh dự đón nhận lá cờ Bác tặng tại mặt trận Điện Biên Phủ. Đây là niềm động viên to lớn giữa thời điểm chiến dịch đang diễn ra ác liệt.\nÝ nghĩa: Sự kiện thể hiện sự quan tâm đặc biệt của Bác đối với những đơn vị trực tiếp chiến đấu, đồng thời tiếp thêm quyết tâm chiến đấu cho bộ đội."},{"num":95,"question":"Nhân dịp kỷ niệm 64 năm ngày sinh của Bác năm 1954, ai là người được cử về báo công với Bác thay mặt đơn vị pháo binh?","options":{"A":"Phùng Văn Khầu","B":"Quan Thông","C":"Vi Văn Vinh","D":"Bùi Đình Cầu"},"answer":"B","explanation":"Quan Thông\nGiải thích mở rộng: Tài liệu phụ lục nêu rõ nhân dịp sinh nhật Bác năm 1954, đồng chí Quan Thông, trung đội trưởng Đại đội 806/Trung đoàn 45, được cử thay mặt đơn vị về báo công với Bác. Đây là vinh dự lớn đối với chiến sĩ pháo binh đang chiến đấu ở Điện Biên Phủ.\nÝ nghĩa: Qua đó càng thấy mối quan hệ gắn bó, thiêng liêng giữa Bác Hồ với bộ đội pháo binh trong những năm kháng chiến gian khổ."},{"num":96,"question":"Ngày 04/5/1957, Bác Hồ và Đại tướng Võ Nguyên Giáp đến theo dõi nội dung gì liên quan đến pháo binh?","options":{"A":"Diễn tập hiệp đồng tại Trường bắn Quốc gia Hòa Lạc","B":"Duyệt đội ngũ tại Hà Nội","C":"Bắn thử tên lửa chiến thuật","D":"Hội nghị cán bộ trung cao cấp"},"answer":"A","explanation":"Diễn tập hiệp đồng tại Trường bắn Quốc gia Hòa Lạc\nGiải thích mở rộng: Ngày 04/5/1957, Bác Hồ và Đại tướng Võ Nguyên Giáp đến thăm, theo dõi cuộc diễn tập hiệp đồng tại Trường bắn Quốc gia Hòa Lạc. Sự kiện cho thấy lãnh đạo Đảng, Nhà nước rất quan tâm đến chất lượng huấn luyện của bộ đội pháo binh.\nÝ nghĩa: Đây là nguồn động viên lớn và cũng là lời nhắc nhở về yêu cầu huấn luyện giỏi, hiệp đồng tốt của lực lượng pháo binh."},{"num":97,"question":"Ngày 21/5/1959, Bác Hồ và Đại tướng Nguyễn Chí Thanh đến dự sự kiện nào của pháo binh?","options":{"A":"Lễ thành lập Đảng bộ Binh chủng","B":"Hội nghị học tập Nghị quyết Trung ương 15 của cán bộ trung, cao cấp pháo binh","C":"Lễ xuất quân vào miền Nam","D":"Hội thao pháo binh toàn quân"},"answer":"B","explanation":"Hội nghị học tập Nghị quyết Trung ương 15 của cán bộ trung, cao cấp pháo binh\nGiải thích mở rộng: Ngày 21/5/1959, Bác Hồ và Đại tướng Nguyễn Chí Thanh dự hội nghị học tập Nghị quyết Trung ương 15 của cán bộ trung, cao cấp pháo binh tại Hà Nội. Điều đó cho thấy công tác chính trị, tư tưởng luôn được đặt ở vị trí rất quan trọng.\nÝ nghĩa: Sự kiện nhấn mạnh truyền thống gắn bó giữa xây dựng chính trị tư tưởng với xây dựng sức mạnh chiến đấu của pháo binh."},{"num":98,"question":"Trong phần truyền thống, câu nào diễn đạt đúng nhất mối quan hệ giữa pháo binh và bộ binh?","options":{"A":"Pháo binh chiến đấu tách rời bộ binh","B":"Tất cả vì bộ binh, vì yêu cầu chiến đấu mà phục vụ vô điều kiện","C":"Bộ binh phục vụ pháo binh là chủ yếu","D":"Hai lực lượng ít liên quan trong hiệp đồng"},"answer":"B","explanation":"Tất cả vì bộ binh, vì yêu cầu chiến đấu mà phục vụ vô điều kiện\nGiải thích mở rộng: Đề cương nhấn mạnh tinh thần tất cả vì bộ binh, vì yêu cầu chiến đấu mà phục vụ vô điều kiện. Đây là tư tưởng hiệp đồng rất sâu sắc của lực lượng pháo binh trong chiến tranh nhân dân.\nÝ nghĩa: Ý nghĩa là người lính pháo binh phải luôn đặt nhiệm vụ chung, hiệu quả chiến đấu chung lên trên hết, sẵn sàng cơ động và chi viện nơi khó khăn nhất."},{"num":99,"question":"Trong kháng chiến chống Mỹ, một trong những cách sử dụng vũ khí cải tiến nổi bật của pháo binh là gì?","options":{"A":"Dùng A12, H12 luồn sâu đánh hiểm vào căn cứ sân bay Mỹ - ngụy","B":"Chỉ dùng sơn pháo 75mm","C":"Chỉ tác chiến phòng ngự bờ biển","D":"Ngừng cải tiến vũ khí"},"answer":"A","explanation":"Dùng A12, H12 luồn sâu đánh hiểm vào căn cứ sân bay Mỹ - ngụy\nGiải thích mở rộng: Theo phần truyền thống làm chủ khoa học kỹ thuật, pháo binh đã nghiên cứu, cải tiến và sử dụng hiệu quả các loại hỏa tiễn như A12, H12 để luồn sâu, đánh hiểm vào các căn cứ, sân bay của Mỹ - ngụy. Đây là sáng tạo rất đáng chú ý của lực lượng.\nÝ nghĩa: Nội dung này chứng minh pháo binh không chỉ giỏi sử dụng trang bị hiện có mà còn biết cải tiến, sáng tạo phù hợp thực tiễn chiến trường."},{"num":100,"question":"Một trong những yêu cầu hiện nay để chiến đấu thắng lợi khi địch sử dụng vũ khí công nghệ cao là gì?","options":{"A":"Giảm huấn luyện cơ động","B":"Nâng cao chất lượng trinh sát, chỉ huy, cơ động và khả năng tác chiến của pháo binh - tên lửa","C":"Tách pháo binh khỏi hiệp đồng binh chủng","D":"Chỉ tăng quân số"},"answer":"B","explanation":"Nâng cao chất lượng trinh sát, chỉ huy, cơ động và khả năng tác chiến của pháo binh - tên lửa\nGiải thích mở rộng: Đề cương nêu rõ trong điều kiện mới, trước đối tượng tác chiến sử dụng vũ khí công nghệ cao, pháo binh - tên lửa phải nâng cao chất lượng trinh sát, chỉ huy, cơ động và khả năng tác chiến. Đây là yêu cầu thực tiễn rất quan trọng.\nÝ nghĩa: Ý nghĩa là phát huy truyền thống phải gắn liền với đổi mới nội dung, phương pháp huấn luyện và nâng cao năng lực chiến đấu trong chiến tranh hiện đại."}],"tfQuestions":[{"num":1,"statement":"Ngày 29/6/1946 được xác định là Ngày truyền thống của Bộ đội Pháo binh - Tên lửa.","answer":true,"explanation":"Giải thích ngắn: Đây là ngày thành lập Đoàn Pháo binh Thủ đô - mốc ra đời chính thức của pháo binh cách mạng Việt Nam. Vì vậy 29/6 hằng năm được lấy làm ngày truyền thống của lực lượng."},{"num":2,"statement":"Đoàn Pháo binh Thủ đô là đơn vị pháo binh đầu tiên của Quân đội nhân dân Việt Nam.","answer":true,"explanation":"Giải thích ngắn: Đơn vị được thành lập ngày 29/6/1946 tại số 40 Hàng Bài, Hà Nội. Đây là tổ chức pháo binh đầu tiên của Quân đội ta."},{"num":3,"statement":"Pháo đài Láng đã nổ phát đạn đầu tiên mở màn toàn quốc kháng chiến tối 19/12/1946.","answer":true,"explanation":"Giải thích ngắn: Sự kiện này gắn với mốc mở đầu toàn quốc kháng chiến chống thực dân Pháp. Nó cũng khẳng định vai trò chiến đấu trực tiếp của pháo binh ngay từ đầu."},{"num":4,"statement":"Năm 1949, Cục Pháo binh được thành lập theo Sắc lệnh 50/SL của Chủ tịch Hồ Chí Minh.","answer":true,"explanation":"Giải thích ngắn: Ngày 18/6/1949, Bác Hồ ký sắc lệnh thành lập Cục Pháo binh. Đây là bước phát triển quan trọng về tổ chức, chỉ huy và chuyên môn hóa."},{"num":5,"statement":"Tiểu đoàn 410 là tiểu đoàn pháo binh đầu tiên của Quân đội ta.","answer":true,"explanation":"Giải thích ngắn: Từ các trung đội, khẩu đội ban đầu, việc thành lập Tiểu đoàn 410 đánh dấu bước trưởng thành mới của pháo binh về tổ chức."},{"num":6,"statement":"Đồng chí Trần Đại Nghĩa là người phụ trách đầu tiên của Cục Pháo binh.","answer":true,"explanation":"Giải thích ngắn: Ông là nhà khoa học quân sự lớn của Việt Nam. Việc ông phụ trách Cục Pháo binh cho thấy vai trò của khoa học kỹ thuật trong xây dựng lực lượng."},{"num":7,"statement":"Đại đoàn Công pháo 351 được thành lập tháng 3 năm 1951.","answer":true,"explanation":"Giải thích ngắn: Đây là đại đoàn công pháo chủ lực của ta trong kháng chiến chống Pháp. Đơn vị có vai trò đặc biệt quan trọng ở Điện Biên Phủ."},{"num":8,"statement":"Trung đoàn 675 là trung đoàn sơn pháo đầu tiên của Binh chủng Pháo binh.","answer":true,"explanation":"Giải thích ngắn: Đơn vị được thành lập trên cơ sở Trung đoàn 95. Đây là mốc quan trọng trong phát triển pháo binh cơ động trên địa hình khó."},{"num":9,"statement":"Trung đoàn 45 là trung đoàn pháo xe kéo đầu tiên của Quân đội nhân dân Việt Nam.","answer":true,"explanation":"Giải thích ngắn: Trung đoàn này tiền thân từ Trung đoàn 34, sau đổi phiên hiệu. Đây là cột mốc quan trọng trong quá trình hiện đại hóa pháo binh."},{"num":10,"statement":"Đại đội 806, Trung đoàn 45 là đơn vị bắn phát đạn đầu tiên vào Him Lam trong Chiến dịch Điện Biên Phủ.","answer":true,"explanation":"Giải thích ngắn: 17 giờ 05 phút ngày 13/3/1954, đơn vị này nổ phát súng mở màn chiến dịch. Hỏa lực pháo binh đã tạo điều kiện quan trọng cho bộ binh tiến công."},{"num":11,"statement":"Ngày 07/9/1954, Bộ Quốc phòng - Tổng Tư lệnh thành lập Bộ Chỉ huy Pháo binh.","answer":true,"explanation":"Giải thích ngắn: Đây là cơ quan chỉ huy đầu tiên của pháo binh trong giai đoạn mới sau thắng lợi chống Pháp. Mốc này rất quan trọng về tổ chức."},{"num":12,"statement":"Ngày 28/5/1956, Bộ Chỉ huy Pháo binh được đổi tên thành Bộ Tư lệnh Pháo binh.","answer":true,"explanation":"Giải thích ngắn: Việc đổi tên phản ánh sự trưởng thành của lực lượng cả về chức năng lẫn vị thế trong Quân đội."},{"num":13,"statement":"Trường Sĩ quan Pháo binh được thành lập ngày 18/02/1957.","answer":true,"explanation":"Giải thích ngắn: Nhà trường có nhiệm vụ đào tạo cán bộ pháo binh cho toàn quân. Đây là nền tảng quan trọng để xây dựng lực lượng chính quy, lâu dài."},{"num":14,"statement":"Ngày 21/3/1958, pháo cao xạ tách khỏi Bộ Tư lệnh Pháo binh để tổ chức Bộ Tư lệnh Phòng không.","answer":true,"explanation":"Giải thích ngắn: Việc điều chỉnh này phù hợp với yêu cầu chuyên môn hóa từng lực lượng. Nó cho thấy tổ chức quân đội ngày càng hoàn thiện."},{"num":15,"statement":"Đảng bộ Binh chủng Pháo binh được thành lập ngày 22/5/1959.","answer":true,"explanation":"Giải thích ngắn: Đây là mốc khẳng định vai trò lãnh đạo tuyệt đối, trực tiếp về mọi mặt của Đảng đối với lực lượng pháo binh."},{"num":16,"statement":"Trong 10 năm xây dựng lực lượng 1954-1964, pháo binh phát triển ở cả bộ đội chủ lực, địa phương và dân quân tự vệ.","answer":true,"explanation":"Giải thích ngắn: Điều đó tạo nên thế trận hỏa lực rộng khắp. Đây là nét đặc trưng của chiến tranh nhân dân Việt Nam."},{"num":17,"statement":"Trong Tổng tiến công và nổi dậy Xuân Mậu Thân 1968, pháo binh đã đánh vào nhiều cơ quan đầu não của Mỹ - ngụy.","answer":true,"explanation":"Giải thích ngắn: Hỏa lực pháo binh tạo tác động mạnh cả về quân sự và tâm lý. Đây là đóng góp đáng kể của binh chủng trong chiến dịch lớn."},{"num":18,"statement":"Chiến dịch Đường 9 - Nam Lào năm 1971 là một trong những chiến dịch lớn ghi dấu sự trưởng thành của pháo binh.","answer":true,"explanation":"Giải thích ngắn: Pháo binh đã phát huy tốt vai trò chi viện hỏa lực trong chiến dịch này. Thành tích ấy được Nhà nước khen thưởng xứng đáng."},{"num":19,"statement":"Trong Chiến dịch Hồ Chí Minh lịch sử, pháo binh hiệp đồng cùng 5 quân đoàn tiến vào giải phóng Sài Gòn.","answer":true,"explanation":"Giải thích ngắn: Điều đó cho thấy quy mô sử dụng pháo binh rất lớn trong trận quyết chiến chiến lược cuối cùng của cuộc kháng chiến chống Mỹ."},{"num":20,"statement":"Ngày 05/8/1965, khi Mỹ mở rộng chiến tranh phá hoại ra miền Bắc, pháo binh ta đã tham gia bắn rơi máy bay và bắn cháy, bắn chìm nhiều tàu chiến Mỹ.","answer":true,"explanation":"Giải thích ngắn: Sự kiện này khẳng định pháo binh có thể tác chiến linh hoạt trong nhiều môi trường. Vai trò bảo vệ miền Bắc của pháo binh rất nổi bật."},{"num":21,"statement":"Ngày 13/4/1967, Bác Hồ tặng bộ đội pháo binh tám chữ vàng 'Chân đồng vai sắt, đánh giỏi, bắn trúng'.","answer":true,"explanation":"Giải thích ngắn: Đây là phần thưởng tinh thần vô cùng quý giá của Bác dành cho bộ đội pháo binh. Tám chữ vàng trở thành truyền thống của lực lượng."},{"num":22,"statement":"Trong thư khen ngày 13/4/1967, Bác Hồ dặn bộ đội pháo binh không được chủ quan, phải học tập và giữ gìn pháo xe tốt.","answer":true,"explanation":"Giải thích ngắn: Lời dặn của Bác vừa mang tính giáo dục chính trị, vừa nhấn mạnh yêu cầu chính quy, làm chủ kỹ thuật của binh chủng."},{"num":23,"statement":"Năm 1979, pháo binh đã chi viện cho các lực lượng vũ trang bảo vệ biên giới và chủ quyền Tổ quốc.","answer":true,"explanation":"Giải thích ngắn: Sau khi đất nước thống nhất, pháo binh vẫn tiếp tục trực tiếp làm nhiệm vụ chiến đấu. Đây là giai đoạn rất quan trọng trong bảo vệ Tổ quốc."},{"num":24,"statement":"Tháng 8/1989, Tiểu đoàn 1 pháo BM-21 của Trung đoàn 204 được cử sang Campuchia giúp bạn.","answer":true,"explanation":"Giải thích ngắn: Đây là biểu hiện cụ thể của tinh thần đoàn kết quốc tế trong sáng. Đơn vị đã hoàn thành tốt nhiệm vụ quốc tế được giao."},{"num":25,"statement":"Từ năm 1991 đến 1995, Binh chủng đã nghiệm thu 36 đề tài khoa học quân sự.","answer":true,"explanation":"Giải thích ngắn: Con số này cho thấy pháo binh rất chú trọng nghiên cứu khoa học, tổng kết thực tiễn và nâng cao chất lượng huấn luyện, chiến đấu."},{"num":26,"statement":"Năm 1996, có 4 lữ đoàn đạt tiêu chuẩn đơn vị vững mạnh toàn diện là 45, 490, 675 và 204.","answer":true,"explanation":"Giải thích ngắn: Kết quả này phản ánh chất lượng xây dựng đơn vị trong thời kỳ đổi mới. Nó cũng cho thấy hiệu quả của phong trào thi đua quyết thắng."},{"num":27,"statement":"Lữ đoàn 96 được thành lập theo Quyết định ngày 20/8/2008 của Bộ Quốc phòng.","answer":true,"explanation":"Giải thích ngắn: Đây là một bước chấn chỉnh tổ chức, biên chế quan trọng của Binh chủng trong giai đoạn 2006-2010."},{"num":28,"statement":"Ngày 02/3/2010, Lữ đoàn 675 được chấn chỉnh thành khung thường trực và bảo quản trang bị thời bình.","answer":true,"explanation":"Giải thích ngắn: Việc điều chỉnh này nhằm phù hợp với yêu cầu tổ chức lực lượng, vừa tiết kiệm vừa vẫn giữ được khả năng sẵn sàng chiến đấu."},{"num":29,"statement":"Ngày 27/02/2015, Trung tâm Huấn luyện - Đào tạo được thành lập trực thuộc Binh chủng Pháo binh.","answer":true,"explanation":"Giải thích ngắn: Đây là bước kiện toàn quan trọng về công tác huấn luyện, đào tạo của binh chủng trong tình hình mới."},{"num":30,"statement":"Nét truyền thống đầu tiên của bộ đội pháo binh - tên lửa là luôn trung thành vô hạn với Tổ quốc, với Đảng, với Nhân dân.","answer":true,"explanation":"Giải thích ngắn: Đây là nền tảng chính trị - tinh thần của toàn bộ truyền thống pháo binh. Mọi chiến công đều bắt nguồn từ lòng trung thành ấy."},{"num":31,"statement":"Nét truyền thống thứ hai của bộ đội pháo binh là dũng cảm mưu trí sáng tạo nhiều cách đánh hay, càng đánh càng mạnh, càng trưởng thành.","answer":true,"explanation":"Giải thích ngắn: Từ Sông Lô đến Điện Biên Phủ, Mậu Thân, 1972 và 1975, pháo binh luôn biết sáng tạo cách đánh phù hợp để giành thắng lợi."},{"num":32,"statement":"Nét truyền thống thứ ba của bộ đội pháo binh là đoàn kết hiệp đồng, lập công tập thể, nêu cao tính kỷ luật tự giác nghiêm minh.","answer":true,"explanation":"Giải thích ngắn: Pháo binh là binh chủng có tính hiệp đồng cao. Vì vậy truyền thống kỷ luật và hiệp đồng mang ý nghĩa đặc biệt quan trọng."},{"num":33,"statement":"Nét truyền thống thứ tư là không ngừng học tập, rèn luyện vươn lên làm chủ khoa học kỹ thuật quân sự.","answer":true,"explanation":"Giải thích ngắn: Đây là yêu cầu khách quan của một binh chủng kỹ thuật. Không làm chủ kỹ thuật thì không thể đánh giỏi, bắn trúng."},{"num":34,"statement":"Nét truyền thống thứ năm là tự lực, tự cường, cần kiệm xây dựng đơn vị, yêu quý giữ gìn và khai thác tốt vũ khí trang bị.","answer":true,"explanation":"Giải thích ngắn: Truyền thống này được hình thành từ hoàn cảnh rất thiếu thốn của những năm đầu. Nó vẫn còn nguyên giá trị đến hôm nay."},{"num":35,"statement":"Nét truyền thống thứ sáu là gắn bó máu thịt với nhân dân, với đơn vị bạn, nêu cao tinh thần đoàn kết quốc tế.","answer":true,"explanation":"Giải thích ngắn: Bộ đội pháo binh là con em nhân dân, từ nhân dân mà ra, vì nhân dân mà chiến đấu. Đây là cội nguồn sức mạnh rất lớn."},{"num":36,"statement":"Đầu xuân 1953, Bác Hồ đến thăm và nói chuyện với Đại đoàn Công pháo 351 ở Bằng Luân, Tuyên Quang.","answer":true,"explanation":"Giải thích ngắn: Sự kiện này gắn với lời dạy nổi tiếng của Bác về vai trò của pháo binh đối với thắng lợi trên chiến trường."},{"num":37,"statement":"Ngày 31/3/1959, Bác Hồ đến thăm Đại đội Pháo binh 34 phòng thủ đảo Hòn Rồng, Quảng Ninh.","answer":true,"explanation":"Giải thích ngắn: Đây là một trong những sự kiện thiêng liêng thể hiện sự quan tâm trực tiếp của Bác với bộ đội pháo binh ở tuyến đảo."},{"num":38,"statement":"Ngày 19/8/1962, Bác Hồ đến thăm Đoàn Pháo binh 374.","answer":true,"explanation":"Giải thích ngắn: Bác căn dặn đơn vị phải luôn luôn sẵn sàng chiến đấu bảo vệ cách mạng, bảo vệ Tổ quốc. Lời dặn này vẫn còn nguyên giá trị."},{"num":39,"statement":"Ngày 17/4/1966, Bác Hồ đến xem hỏa tiễn A12 do Bộ Tư lệnh Pháo binh cải tiến và ĐKB tại Hòa Lạc.","answer":true,"explanation":"Giải thích ngắn: Sự kiện phản ánh truyền thống nghiên cứu, cải tiến kỹ thuật của lực lượng pháo binh trong kháng chiến chống Mỹ."},{"num":40,"statement":"Đầu năm 1969, Bác Hồ gặp mặt, tặng hoa và huy hiệu cho 3 chiến sĩ hải pháo có thành tích bắn cháy, bắn chìm tàu chiến Mỹ.","answer":true,"explanation":"Giải thích ngắn: Đây là phần thưởng cao quý, thể hiện sự ghi nhận kịp thời của Bác đối với chiến công của bộ đội pháo binh."},{"num":41,"statement":"Bộ Tư lệnh Pháo binh - Tên lửa cùng 82 đơn vị và 17 cán bộ, chiến sĩ đã được phong tặng danh hiệu Anh hùng LLVTND.","answer":true,"explanation":"Giải thích ngắn: Đây là thành tích đặc biệt vẻ vang của toàn lực lượng qua 80 năm xây dựng, chiến đấu và trưởng thành."},{"num":42,"statement":"Binh chủng Pháo binh được phong tặng danh hiệu Anh hùng LLVTND ngày 03/6/1976.","answer":true,"explanation":"Giải thích ngắn: Đây là sự ghi nhận rất cao của Đảng và Nhà nước đối với công lao, chiến công của lực lượng trong kháng chiến."},{"num":43,"statement":"Ngày 26/11/2000, Binh chủng Pháo binh được nhận Giải thưởng Hồ Chí Minh.","answer":true,"explanation":"Giải thích ngắn: Giải thưởng gắn với cụm công trình về nghệ thuật quân sự của bộ đội pháo binh trong cuộc kháng chiến chống Mỹ cứu nước."},{"num":44,"statement":"Ngày 22/4/2006, Binh chủng Pháo binh được tặng Huân chương Sao vàng.","answer":true,"explanation":"Giải thích ngắn: Đây là phần thưởng cao quý nhất của Đảng và Nhà nước, khẳng định tầm vóc lịch sử của lực lượng pháo binh."},{"num":45,"statement":"Ngày 21/12/2010, Binh chủng Pháo binh được tặng Huân chương Quân công hạng Nhất.","answer":true,"explanation":"Giải thích ngắn: Phần thưởng này ghi nhận thành tích xuất sắc của Binh chủng trong giai đoạn 2005-2010."},{"num":46,"statement":"Năm 2014, Binh chủng Pháo binh được Nhà nước Campuchia tặng Huy chương Hữu nghị hạng Thập-Ba-Đân.","answer":true,"explanation":"Giải thích ngắn: Phần thưởng thể hiện sự ghi nhận của bạn bè quốc tế đối với đóng góp và tình đoàn kết của bộ đội pháo binh."},{"num":47,"statement":"Trong kháng chiến chống Pháp, bộ đội pháo binh được tặng 25 Huân chương Quân công.","answer":true,"explanation":"Giải thích ngắn: Đây là con số nêu trong đề cương tổng kết thành tích của lực lượng sau thắng lợi kháng chiến chống thực dân Pháp."},{"num":48,"statement":"Trong kháng chiến chống Pháp, bộ đội pháo binh được tặng 594 Huân chương Chiến công.","answer":true,"explanation":"Giải thích ngắn: Con số này cho thấy phạm vi chiến công rất rộng của các tập thể, cá nhân thuộc lực lượng pháo binh."},{"num":49,"statement":"Liệt sĩ Trịnh Thế Xương được truy tặng danh hiệu Anh hùng LLVTND ngày 28/4/2000.","answer":true,"explanation":"Giải thích ngắn: Đồng chí là tấm gương tiêu biểu của Trung đoàn 675. Việc truy tặng góp phần giáo dục truyền thống anh hùng cho thế hệ sau."},{"num":50,"statement":"Ngày truyền thống của Bộ đội Pháo binh - Tên lửa là 19/12/1946.","answer":false,"explanation":"Giải thích ngắn: 19/12/1946 là ngày toàn quốc kháng chiến và gắn với phát đạn đầu tiên của Pháo đài Láng. Ngày truyền thống của lực lượng là 29/6/1946."},{"num":51,"statement":"Đơn vị pháo binh đầu tiên của Quân đội ta là Cục Pháo binh.","answer":false,"explanation":"Giải thích ngắn: Cục Pháo binh là cơ quan chuyên môn được thành lập năm 1949. Đơn vị pháo binh đầu tiên là Đoàn Pháo binh Thủ đô, thành lập năm 1946."},{"num":52,"statement":"Phát đạn mở màn toàn quốc kháng chiến được bắn từ pháo đài Xuân Canh.","answer":false,"explanation":"Giải thích ngắn: Phát đạn đầu tiên mở màn toàn quốc kháng chiến được bắn từ Pháo đài Láng tối 19/12/1946."},{"num":53,"statement":"Cục Pháo binh được thành lập vào năm 1951 cùng thời điểm với Đại đoàn 351.","answer":false,"explanation":"Giải thích ngắn: Cục Pháo binh được thành lập ngày 18/6/1949. Đại đoàn Công pháo 351 được thành lập sau đó, vào tháng 3/1951."},{"num":54,"statement":"Người phụ trách đầu tiên của Cục Pháo binh là đồng chí Lê Thiết Hùng.","answer":false,"explanation":"Giải thích ngắn: Người phụ trách đầu tiên của Cục Pháo binh là đồng chí Trần Đại Nghĩa. Lê Thiết Hùng là Tư lệnh khi Bộ Tư lệnh Pháo binh được thành lập năm 1956."},{"num":55,"statement":"Đại đoàn Công pháo 351 được thành lập sau chiến thắng Điện Biên Phủ.","answer":false,"explanation":"Giải thích ngắn: Đại đoàn 351 được thành lập từ tháng 3/1951, trước chiến thắng Điện Biên Phủ nhiều năm. Đây là lực lượng nòng cốt tham gia chiến dịch này."},{"num":56,"statement":"Trung đoàn 675 là trung đoàn pháo xe kéo đầu tiên của Quân đội ta.","answer":false,"explanation":"Giải thích ngắn: Trung đoàn 675 là trung đoàn sơn pháo đầu tiên. Trung đoàn 45 mới là trung đoàn pháo xe kéo đầu tiên."},{"num":57,"statement":"Trung đoàn 45 là trung đoàn sơn pháo đầu tiên của Binh chủng.","answer":false,"explanation":"Giải thích ngắn: Trung đoàn 45 là trung đoàn pháo xe kéo đầu tiên. Trung đoàn 675 mới là trung đoàn sơn pháo đầu tiên."},{"num":58,"statement":"Đơn vị bắn phát đạn đầu tiên vào Him Lam là Trung đoàn 675.","answer":false,"explanation":"Giải thích ngắn: Đơn vị bắn phát đạn đầu tiên vào Him Lam là Đại đội 806 thuộc Trung đoàn 45 vào 17 giờ 05 phút ngày 13/3/1954."},{"num":59,"statement":"Ngày 07/9/1954, Bộ Tư lệnh Pháo binh chính thức ra đời.","answer":false,"explanation":"Giải thích ngắn: Ngày 07/9/1954 mới thành lập Bộ Chỉ huy Pháo binh. Đến 28/5/1956 mới đổi tên thành Bộ Tư lệnh Pháo binh."},{"num":60,"statement":"Thiếu tướng Lê Thiết Hùng là Tư lệnh kiêm Chính ủy Bộ Chỉ huy Pháo binh ngay từ ngày 07/9/1954.","answer":false,"explanation":"Giải thích ngắn: Ngày 07/9/1954, đồng chí Nguyễn Chánh là Tư lệnh kiêm Chính ủy Bộ Chỉ huy Pháo binh. Lê Thiết Hùng làm Tư lệnh khi Bộ Tư lệnh Pháo binh được thành lập năm 1956."},{"num":61,"statement":"Trường Sĩ quan Pháo binh được thành lập vào ngày 22/5/1959.","answer":false,"explanation":"Giải thích ngắn: Ngày 22/5/1959 là ngày thành lập Đảng bộ Binh chủng Pháo binh. Trường Sĩ quan Pháo binh thành lập ngày 18/02/1957."},{"num":62,"statement":"Ngày 21/3/1958, pháo binh mặt đất tách khỏi Bộ Tư lệnh Pháo binh để thành lập Bộ Tư lệnh Phòng không.","answer":false,"explanation":"Giải thích ngắn: Ngày này là mốc pháo cao xạ tách ra để tổ chức Bộ Tư lệnh Phòng không, không phải pháo binh mặt đất."},{"num":63,"statement":"Đảng bộ Binh chủng Pháo binh được thành lập trước khi có Bộ Tư lệnh Pháo binh.","answer":false,"explanation":"Giải thích ngắn: Bộ Tư lệnh Pháo binh thành lập năm 1956. Đảng bộ Binh chủng Pháo binh được thành lập sau đó, ngày 22/5/1959."},{"num":64,"statement":"Trong giai đoạn 1954-1964, pháo binh chỉ phát triển trong khối chủ lực, chưa có ở địa phương và dân quân tự vệ.","answer":false,"explanation":"Giải thích ngắn: Theo đề cương, pháo binh phát triển rộng ở cả bộ đội chủ lực, bộ đội địa phương và dân quân tự vệ."},{"num":65,"statement":"Trong Xuân Mậu Thân 1968, pháo binh chủ yếu chỉ làm nhiệm vụ vận chuyển đạn.","answer":false,"explanation":"Giải thích ngắn: Pháo binh trực tiếp tham gia tiến công và chi viện hỏa lực, đánh vào nhiều cơ quan đầu não của Mỹ - ngụy trên toàn chiến trường."},{"num":66,"statement":"Chiến dịch Đường 9 - Nam Lào diễn ra năm 1972.","answer":false,"explanation":"Giải thích ngắn: Chiến dịch Đường 9 - Nam Lào được tài liệu nhấn mạnh ở năm 1971. Năm 1972 gắn với cuộc Tổng tiến công chiến lược."},{"num":67,"statement":"Trong Chiến dịch Hồ Chí Minh, pháo binh chỉ hiệp đồng với 3 quân đoàn.","answer":false,"explanation":"Giải thích ngắn: Tài liệu nêu quy mô hiệp đồng là 5 quân đoàn cùng nhiều lực lượng khác tiến vào giải phóng Sài Gòn."},{"num":68,"statement":"Ngày 05/8/1965, pháo binh ta chủ yếu rút lui, chưa tham gia đánh trả Mỹ.","answer":false,"explanation":"Giải thích ngắn: Khi Mỹ mở rộng chiến tranh phá hoại ra miền Bắc, pháo binh ta đã tham gia bắn rơi máy bay, bắn cháy và bắn chìm nhiều tàu chiến Mỹ."},{"num":69,"statement":"Tám chữ vàng Bác Hồ tặng bộ đội pháo binh là 'Đoàn kết, kỷ luật, quyết thắng, lập công'.","answer":false,"explanation":"Giải thích ngắn: Tám chữ vàng đúng là 'Chân đồng vai sắt, đánh giỏi, bắn trúng'. Đây là truyền thống tiêu biểu của lực lượng."},{"num":70,"statement":"Trong thư khen năm 1967, Bác Hồ dặn bộ đội pháo binh có thể chủ quan vì đã thắng lớn.","answer":false,"explanation":"Giải thích ngắn: Bác Hồ căn dặn điều ngược lại: không được chủ quan, phải tiếp tục học tập, rèn luyện và giữ gìn pháo xe tốt."},{"num":71,"statement":"Năm 1979, pháo binh chỉ làm nhiệm vụ kinh tế, không trực tiếp chiến đấu.","answer":false,"explanation":"Giải thích ngắn: Năm 1979, pháo binh đã chi viện cho các lực lượng vũ trang chiến đấu, góp phần bảo vệ biên giới và chủ quyền Tổ quốc."},{"num":72,"statement":"Tháng 8/1989, Trung đoàn 675 được cử sang Campuchia giúp bạn huấn luyện BM-21.","answer":false,"explanation":"Giải thích ngắn: Đơn vị được cử sang Campuchia là Tiểu đoàn 1 pháo BM-21 của Trung đoàn 204."},{"num":73,"statement":"Giai đoạn 1991-1995, Binh chủng chỉ nghiệm thu 21 đề tài tổng kết quân sự, không có đề tài khoa học quân sự.","answer":false,"explanation":"Giải thích ngắn: Ngoài 21 công trình tổng kết quân sự, Binh chủng còn nghiệm thu 36 đề tài khoa học quân sự và 49 đề tài khoa học kỹ thuật quân sự."},{"num":74,"statement":"Năm 1996 chỉ có 2 lữ đoàn đạt tiêu chuẩn đơn vị vững mạnh toàn diện.","answer":false,"explanation":"Giải thích ngắn: Theo tài liệu, có 4 lữ đoàn đạt tiêu chuẩn này: 45, 490, 675 và 204."},{"num":75,"statement":"Lữ đoàn 96 được thành lập theo quyết định ngày 02/3/2010.","answer":false,"explanation":"Giải thích ngắn: Lữ đoàn 96 được thành lập theo quyết định ngày 20/8/2008. Ngày 02/3/2010 gắn với việc chấn chỉnh Lữ đoàn 675."},{"num":76,"statement":"Ngày 27/02/2015 là ngày thành lập Lữ đoàn 96.","answer":false,"explanation":"Giải thích ngắn: Ngày 27/02/2015 là mốc thành lập Trung tâm Huấn luyện - Đào tạo trực thuộc Binh chủng Pháo binh."},{"num":77,"statement":"Nét truyền thống đầu tiên của bộ đội pháo binh là gắn bó máu thịt với nhân dân.","answer":false,"explanation":"Giải thích ngắn: Gắn bó máu thịt với nhân dân là nét truyền thống thứ sáu. Nét thứ nhất là trung thành vô hạn với Tổ quốc, với Đảng, với Nhân dân."},{"num":78,"statement":"Nét truyền thống thứ hai của pháo binh là tự lực, tự cường, cần kiệm xây dựng đơn vị.","answer":false,"explanation":"Giải thích ngắn: Tự lực, tự cường, cần kiệm xây dựng đơn vị là nét truyền thống thứ năm. Nét thứ hai là dũng cảm, mưu trí, sáng tạo nhiều cách đánh hay."},{"num":79,"statement":"Nét truyền thống thứ ba của bộ đội pháo binh là làm chủ khoa học kỹ thuật quân sự.","answer":false,"explanation":"Giải thích ngắn: Làm chủ khoa học kỹ thuật quân sự là nét truyền thống thứ tư. Nét thứ ba là đoàn kết hiệp đồng, lập công tập thể, kỷ luật nghiêm minh."},{"num":80,"statement":"Nét truyền thống thứ tư của pháo binh là gắn bó máu thịt với nhân dân và đoàn kết quốc tế.","answer":false,"explanation":"Giải thích ngắn: Đó là nét truyền thống thứ sáu. Nét thứ tư là không ngừng học tập, rèn luyện làm chủ khoa học kỹ thuật quân sự."},{"num":81,"statement":"Nét truyền thống thứ năm của bộ đội pháo binh là đoàn kết hiệp đồng, lập công tập thể.","answer":false,"explanation":"Giải thích ngắn: Đoàn kết hiệp đồng là nét truyền thống thứ ba. Nét thứ năm là tự lực, tự cường, cần kiệm xây dựng đơn vị, giữ gìn vũ khí trang bị."},{"num":82,"statement":"Nét truyền thống thứ sáu là dũng cảm mưu trí sáng tạo nhiều cách đánh hay.","answer":false,"explanation":"Giải thích ngắn: Đó là nét truyền thống thứ hai. Nét thứ sáu là gắn bó máu thịt với nhân dân, với đơn vị bạn, nêu cao tinh thần đoàn kết quốc tế."},{"num":83,"statement":"Đầu xuân 1953, Bác Hồ đến thăm Trung đoàn 204 ở miền Nam.","answer":false,"explanation":"Giải thích ngắn: Đầu xuân 1953, Bác Hồ đến thăm Đại đoàn Công pháo 351 ở Bằng Luân, Tuyên Quang."},{"num":84,"statement":"Ngày 31/3/1959, Bác Hồ đến thăm Đoàn Pháo binh 374.","answer":false,"explanation":"Giải thích ngắn: Ngày 31/3/1959, Bác đến thăm Đại đội Pháo binh 34 phòng thủ đảo Hòn Rồng. Đoàn 374 được Bác đến thăm vào ngày 19/8/1962."},{"num":85,"statement":"Ngày 19/8/1962, Bác Hồ đến thăm Trung đoàn 45.","answer":false,"explanation":"Giải thích ngắn: Ngày 19/8/1962, Bác đến thăm Đoàn Pháo binh 374 và căn dặn đơn vị luôn sẵn sàng chiến đấu."},{"num":86,"statement":"Ngày 17/4/1966, Bác Hồ đến xem tên lửa Scud-B do Bộ Tư lệnh Pháo binh cải tiến.","answer":false,"explanation":"Giải thích ngắn: Bác đến xem hỏa tiễn A12 do Bộ Tư lệnh Pháo binh cải tiến và ĐKB, không phải Scud-B."},{"num":87,"statement":"Đầu năm 1969, Bác Hồ gặp mặt 3 chiến sĩ kéo pháo ở Điện Biên Phủ.","answer":false,"explanation":"Giải thích ngắn: Bác gặp mặt, tặng hoa và huy hiệu cho 3 chiến sĩ hải pháo có thành tích bắn cháy, bắn chìm tàu chiến Mỹ ở Quảng Bình."},{"num":88,"statement":"Bộ Tư lệnh Pháo binh - Tên lửa cùng 62 đơn vị và 17 cán bộ, chiến sĩ được phong tặng danh hiệu Anh hùng LLVTND.","answer":false,"explanation":"Giải thích ngắn: Con số đúng trong đề cương là Bộ Tư lệnh cùng 82 đơn vị và 17 cán bộ, chiến sĩ."},{"num":89,"statement":"Binh chủng Pháo binh được phong tặng danh hiệu Anh hùng LLVTND vào năm 1979.","answer":false,"explanation":"Giải thích ngắn: Binh chủng được phong tặng danh hiệu Anh hùng LLVTND ngày 03/6/1976. Năm 1979 gắn với Huân chương Hồ Chí Minh hạng Nhì."},{"num":90,"statement":"Ngày 26/11/2000, Binh chủng Pháo binh được nhận Huân chương Sao vàng.","answer":false,"explanation":"Giải thích ngắn: Ngày 26/11/2000, Binh chủng nhận Giải thưởng Hồ Chí Minh. Huân chương Sao vàng được tặng ngày 22/4/2006."},{"num":91,"statement":"Ngày 22/4/2006, Binh chủng Pháo binh được tặng Huân chương Độc lập hạng Nhất.","answer":false,"explanation":"Giải thích ngắn: Ngày 22/4/2006 là mốc nhận Huân chương Sao vàng. Huân chương Độc lập hạng Nhất được trao ngày 16/3/2001."},{"num":92,"statement":"Ngày 21/12/2010, Binh chủng Pháo binh được tặng Huân chương Hồ Chí Minh.","answer":false,"explanation":"Giải thích ngắn: Ngày 21/12/2010, Binh chủng được tặng Huân chương Quân công hạng Nhất, không phải Huân chương Hồ Chí Minh."},{"num":93,"statement":"Năm 2014, Binh chủng Pháo binh được Nhà nước Campuchia tặng Huân chương Độc lập.","answer":false,"explanation":"Giải thích ngắn: Phần thưởng của Nhà nước Campuchia là Huy chương Hữu nghị hạng Thập-Ba-Đân."},{"num":94,"statement":"Trong kháng chiến chống Pháp, bộ đội pháo binh được tặng 35 Huân chương Quân công.","answer":false,"explanation":"Giải thích ngắn: Con số đúng theo đề cương là 25 Huân chương Quân công."},{"num":95,"statement":"Trong kháng chiến chống Pháp, bộ đội pháo binh được tặng 494 Huân chương Chiến công.","answer":false,"explanation":"Giải thích ngắn: Con số đúng là 594 Huân chương Chiến công."},{"num":96,"statement":"Liệt sĩ Trịnh Thế Xương được truy tặng danh hiệu Anh hùng LLVTND ngày 28/4/1970.","answer":false,"explanation":"Giải thích ngắn: Mốc đúng là ngày 28/4/2000. Đây là sự ghi nhận muộn nhưng rất xứng đáng đối với tấm gương anh hùng của đồng chí."},{"num":97,"statement":"Trong truyền thống của pháo binh, 'đánh giỏi' không nhất thiết phải gắn với 'bắn trúng'.","answer":false,"explanation":"Giải thích ngắn: Đề cương nêu rất rõ: với bộ đội pháo binh, muốn đánh giỏi thì phải bắn trúng, đúng thời cơ, hiệu suất chiến đấu cao."},{"num":98,"statement":"Pháo binh là lực lượng hậu cần chuyên trách, không phải hỏa lực chủ yếu mặt đất.","answer":false,"explanation":"Giải thích ngắn: Theo đề cương, pháo binh là hỏa lực chủ yếu mặt đất trong tác chiến hiệp đồng binh chủng và đồng thời là binh chủng kỹ thuật."},{"num":99,"statement":"Giáo dục truyền thống 80 năm chủ yếu để ghi nhớ mốc lịch sử, không cần gắn với trách nhiệm hiện nay.","answer":false,"explanation":"Giải thích ngắn: Mục đích sâu xa của giáo dục truyền thống là khơi dậy niềm tự hào, trách nhiệm và động lực phấn đấu hoàn thành tốt nhiệm vụ trong giai đoạn mới."},{"num":100,"statement":"Phong trào 'Một người biết, hai người giỏi' phản ánh tinh thần học tập, làm chủ kỹ thuật của bộ đội pháo binh.","answer":true,"explanation":"Giải thích ngắn: Đây là phong trào nổi bật trong giai đoạn 1954-1964 của pháo binh. Nó khuyến khích lan tỏa kiến thức, nâng cao trình độ toàn đơn vị."}]};